INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('XLV_2021_consolidated', 'XLV', 2021, 'consolidated', 'Công ty có giao dịch tạm ứng/thu hồi với các thành viên Ban Tổng Giám đốc (tạm ứng 1.24 tỷ VND) và Ban kiểm soát (tạm ứng 2 tỷ VND). Phải thu ngắn hạn từ CBNV là bên liên quan là 2.75 tỷ VND. Các giao dịch này mang tính chất tạm ứng chi phí công việc, chưa phát hiện dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn với bên liên quan. Tuy nhiên, cần theo dõi các khoản tạm ứng này có được thu hồi kịp thời hay không.', 'Công ty có khoản vay ngắn hạn tại Vietcombank Chi nhánh Quang Trung với số dư cuối năm 4.73 tỷ VND, lãi suất 6.8%/năm, hạn mức tối đa 20 tỷ VND, thời hạn vay 6 tháng mỗi lần nhận nợ. Khoản vay được đảm bảo bằng toàn bộ quyền sử dụng đất (TSCĐ vô hình trị giá 2.09 tỷ VND), quyền sở hữu nhà ở và xe ô tô. Công ty đánh giá có khả năng trả được khoản vay ngắn hạn. Không có nợ dài hạn. Tổng nợ phải trả 89.9 tỷ VND so với tổng tài sản 138.4 tỷ VND, tỷ lệ nợ khoảng 65%, ở mức cao.', 'Hàng tồn kho cuối năm 35.8 tỷ VND, giảm so với đầu năm 42.4 tỷ VND. Trong đó, chi phí sản xuất kinh doanh dở dang chiếm 24.5 tỷ VND với nhiều công trình điện trọng điểm (trạm biến áp 220KV Sơn Đông, đường dây 500KV Dốc Sỏi - Pleiku, Sông Hậu - Đức Hòa, Quảng Trạch, trạm 220kV Châu Thành). Giá trị dở dang giảm từ 39.2 tỷ VND xuống 24.5 tỷ VND cho thấy tiến độ thi công tốt. Không có dự phòng giảm giá hàng tồn kho. Rủi ro tồn kho ở mức trung bình do tính chất dự án xây dựng điện dài hạn, phụ thuộc vào tiến độ nghiệm thu và thanh toán từ chủ đầu tư (các Ban quản lý dự án điện).', 3, 'Công ty Cổ phần Xây lắp và Dịch vụ Sông Đà đạt kết quả kinh doanh tích cực năm 2021 với doanh thu thuần 271.2 tỷ VND (tăng 29.3% so với năm trước), lợi nhuận sau thuế 2.86 tỷ VND (tăng 10.5%). Biên lợi nhuận gộp đạt 5.59%, ở mức thấp đặc thù ngành xây lắp điện. Điểm đáng lưu ý là dòng tiền từ hoạt động kinh doanh âm nặng (-23.9 tỷ VND) do phải thu ngắn hạn tăng mạnh 20.1 tỷ VND (chủ yếu từ các Ban quản lý dự án điện) và người mua trả trước giảm 8.4 tỷ VND, phản ánh áp lực thu tiền từ khách hàng. Tiền mặt giảm mạnh từ 23.7 tỷ xuống chỉ còn 2.2 tỷ VND. Công ty có hệ thống quản trị minh bạch, giao dịch với bên liên quan chủ yếu là tạm ứng cho nhân viên quản lý ở mức hợp lý. Về triển vọng, công ty là nhà thầu xây lắp điện uy tín với nhiều dự án trọng điểm quốc gia, tuy nhiên cần cải thiện quản lý dòng tiền và duy trì quan hệ tốt với các chủ đầu tư để đảm bảo thu hồi công nợ kịp thời.'),
('XLV_2020_consolidated', 'XLV', 2020, 'consolidated', 'Công ty có giao dịch tạm ứng thi công công trình với ông Nguyễn Anh Tuấn (Thành viên HĐQT kiêm Phó Tổng Giám đốc) với tổng số tiền tạm ứng 6,42 tỷ VNĐ trong năm, đã hoàn lại 6,24 tỷ VNĐ. Ông Trần Xuân Minh (Thành viên HĐQT kiêm Tổng Giám đốc) cũng có giao dịch tạm ứng/hoàn tạm ứng 50 triệu VNĐ. Công ty cho biết không có công nợ tồn đọng với các bên liên quan tại cuối kỳ. Tuy nhiên, việc các thành viên HĐQT kiêm nhiệm cả vai trò điều hành (Tổng Giám đốc, Phó Tổng Giám đốc, Kế toán trưởng) tạo ra rủi ro về xung đột lợi ích và thiếu sự giám sát độc lập.', 'Công ty có vị thế nợ vay rất thấp - không còn dư nợ vay ngân hàng tại cuối năm 2020 (đầu năm có 1.14 tỷ VNĐ nợ ngắn hạn). Tài sản thế chấp là quyền sử dụng đất tại Hà Nội và TP.HCM đã được dùng để đảm bảo cho khoản vay tại Vietinbank Chi nhánh Quang Trung. Áp lực trả nợ gần như không tồn tại, chi phí lãi vay chỉ 28.6 triệu VNĐ trong năm. Tuy nhiên, dòng tiền hoạt động kinh doanh âm 8.8 tỷ VNĐ cho thấy áp lực tiền mặt từ hoạt động kinh doanh.', 'Tồn kho tăng mạnh 63.8% từ 25.9 tỷ lên 42.4 tỷ VNĐ, chủ yếu do chi phí sản xuất kinh doanh dở dang tăng từ 20.8 tỷ lên 39.2 tỷ VNĐ. Các công trình dở dang lớn bao gồm trạm biến áp 220 KV Sơn Đông (14.2 tỷ), đường dây 500 KV Đốc Sỏi-Pleiku (5.4 tỷ), đường dây 500 KV Quảng Trạch (2.5 tỷ), đường dây 500 KV Sông Hậu-Đức Hòa (1.6 tỷ). Đây đều là các công trình điện trọng điểm quốc gia cho EVN, rủi ro ứ đọng thấp do tính chất dự án dài hạn và chủ đầu tư là tập đoàn nhà nước. Tuy nhiên, việc tăng mạnh hàng dở dang kết hợp với doanh thu giảm 22.5% đặt câu hỏi về tiến độ thi công và khả năng thu hồi vốn.', 6, 'Công ty Cổ phần Xây lắp và Dịch vụ Sông Đà là đơn vị thành viên của hệ sinh thái Tổng công ty Sông Đà, hoạt động chính trong lĩnh vực xây lắp đường dây tải điện và trạm biến áp phục vụ EVN. Năm 2020, doanh thu thuần giảm 22.5% (từ 270.6 tỷ xuống 209.7 tỷ VNĐ), lợi nhuận sau thuế giảm 58.8% (từ 6.3 tỷ xuống 2.6 tỷ VNĐ) do ảnh hưởng của đại dịch COVID-19 và giảm quy mô hoạt động xây lắp. Điểm đáng lo ngại: (1) Dòng tiền hoạt động kinh doanh âm 8.8 tỷ VNĐ liên tục hai năm; (2) Công ty chi trả cổ tức 3 tỷ VNĐ (vượt lợi nhuận sau thuế 2.6 tỷ VNĐ); (3) Ban lãnh đạo kiêm nhiệm nhiều vị trí (HĐQT kiêm CEO, Phó CEO, Kế toán trưởng); (4) Mối quan hệ gia đình trong HĐQT (Trần Xuân Chính - Trần Xuân Minh là anh em). Điểm tích cực: không còn nợ vay ngân hàng, tỷ suất lợi nhuận gộp cải thiện nhẹ, không có dự phòng giảm giá hàng tồn kho. Triển vọng trung hạn phụ thuộc vào tiến độ các dự án điện trọng điểm của EVN.'),
('XMC_2015_parent', 'XMC', 2015, 'parent', 'Doanh nghiệp có mạng lưới giao dịch phức tạp với nhiều công ty con, công ty liên kết và bên liên quan khác. Các giao dịch bao gồm mua bán hàng hóa, cho vay, vay mượn với lãi suất khác nhau. Đáng chú ý: (1) Công ty cho Công ty TNHH MTV Cơ khí và Xây dựng Megastar vay 3,3 tỷ đã phải trích lập dự phòng toàn bộ; (2) Các khoản phải thu từ Tổng Công ty PTPT truyền hình thông tin lên tới 119,6 tỷ (góp vốn hợp tác kinh doanh dự án Mễ Trì); (3) Có nhiều khoản vay qua lại giữa công ty mẹ và công ty con với lãi suất không rõ ràng; (4) Khoản trả trước cho người bán với Công ty TNHH MTV Bê tông Xuân Mai lên tới 87 tỷ - mức khá lớn so với quy mô giao dịch.', 'Tổng nợ vay đạt 1.594 tỷ VNĐ, tăng mạnh so với đầu năm (784 tỷ), cho thấy doanh nghiệp đang mở rộng quy mô bằng đòn bẩy tài chính. Nợ ngắn hạn chiếm phần lớn (1.144 tỷ), tạo áp lực thanh khoản đáng kể. Chi phí lãi vay trong năm đạt 59,5 tỷ, tăng 55% so với năm trước (38,3 tỷ). Tài sản thế chấp bao gồm bất động sản chính (tòa nhà CT2), quyền phát sinh từ dự án CT2 Hành chính, cổ phiếu Điện Việt Lào và dây chuyền sản xuất Acotec. Công ty vay từ 2 ngân hàng chính (BIDV và LienVietPostBank) với lãi suất dao động 7-10%/năm, ngoài ra còn vay từ công ty con.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang (787,7 tỷ/791,9 tỷ tổng tồn kho), phản ánh nhiều dự án xây dựng đang triển khai. Tài sản dở dang dài hạn thêm 46,3 tỷ bao gồm các dự án chung cư và xây dựng cơ bản. Công ty đánh giá thận trọng và tin tưởng vào khả năng chuyển nhượng hoặc tiếp tục thực hiện các dự án. Không có dự phòng giảm giá hàng tồn kho. Rủi ro đến từ việc dự án có thể chậm tiến độ hoặc thị trường bất động sản suy giảm.', 6, 'Công ty Cổ phần Đầu tư và Xây dựng Xuân Mai hoạt động trong lĩnh vực xây dựng, bất động sản và sản xuất vật liệu xây dựng với mạng lưới 7 công ty con và 3 công ty liên kết. Doanh thu năm 2015 tăng trưởng 34% đạt 1.769 tỷ, nhưng lợi nhuận gộp giảm nhẹ do biên lợi nhuận gộp giảm từ 10,6% xuống 7,6%. Công ty đang trong giai đoạn mở rộng mạnh mẽ với vốn điều lệ tăng từ 200 tỷ lên 300 tỷ và tổng tài sản tăng 60% từ 1.871 tỷ lên 2.997 tỷ. Tuy nhiên, nợ vay tăng mạnh gấp đôi, tạo áp lực tài chính đáng kể. Lợi nhuận sau thuế đạt 30,7 tỷ (giảm 65% so với năm trước). Công ty có nhiều giao dịch phức tạp với bên liên quan và mạng lưới công ty con/chị em, đòi hỏi giám sát chặt chẽ. Triển vọng phụ thuộc vào tiến độ các dự án bất động sản và khả năng quản lý dòng tiền trong bối cảnh nợ vay cao.'),
('XLV_2019_consolidated', 'XLV', 2019, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là tạm ứng cho thành viên ban điều hành cho mục đích thi công công trình, không có lãi suất, giá trị không lớn so với tổng tài sản, rủi ro thấp.', 'Nợ vay ngắn hạn với lãi suất thả nổi, được đảm bảo bằng tài sản, quy mô nhỏ so với tài sản, áp lực nợ thấp.', 'Tồn kho bao gồm nguyên vật liệu và chi phí xây dựng dở dang, cần theo dõi tiến độ thi công để tránh ứ đọng.', 3, 'Công ty có lợi nhuận ổn định, vốn chủ sở hữu dương, nợ vay ít, hoạt động kinh doanh chính là xây lắp và dịch vụ, triển vọng trung bình.'),
('XDH_2025_consolidated', 'XDH', 2025, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan, đặc biệt là Tổng Công ty UDIC (cổ đông lớn) và các cá nhân trong Hội đồng quản trị. Các giao dịch bao gồm mua bán hàng hóa, thanh toán công nợ và góp vốn. Tuy nhiên, không có dấu hiệu bất thường rõ ràng về giá hay điều kiện giao dịch trong thuyết minh, nhưng cần lưu ý về sự phụ thuộc vào các bên liên quan này.', 'Tổng nợ vay là 37.4 tỷ VNĐ, bao gồm khoản vay ngắn hạn từ BIDV có tài sản thế chấp bất động sản và khoản vay dài hạn không lãi suất từ Vạn Xuân. Áp lực trả nợ ngắn hạn không quá lớn so với dòng tiền kinh doanh, nhưng việc thế chấp bất động sản đầu tư có thể ảnh hưởng đến tính thanh khoản nếu cần xử lý.', 'Hàng tồn kho dở dang chiếm tỷ trọng lớn (trên 411 tỷ VNĐ), bao gồm nhiều dự án bất động sản và công trình xây dựng. Rủi ro chính là tiến độ triển khai và khả năng bán được sản phẩm của các dự án này. Dự phòng giảm giá chỉ áp dụng cho nguyên liệu vật liệu, không áp dụng cho tồn kho dở dang.', 6, 'Công ty hoạt động trong lĩnh vực xây dựng và kinh doanh bất động sản, có quy mô vốn chủ sở hữu lớn (270 tỷ VNĐ). Lợi nhuận sau thuế tăng trưởng tốt (32.7 tỷ VNĐ năm 2025 so với 21 tỷ năm 2024). Tuy nhiên, công ty có nợ vay, hàng tồn kho dở dang lớn và nhiều giao dịch với bên liên quan. Rủi ro chính nằm ở tiến độ triển khai các dự án bất động sản và khả năng thu hồi công nợ. Công ty đang tham gia tranh chấp pháp lý với Công ty Cầu Đường về dự án E4 Yên Hòa, nhưng bản án phúc thẩm đã có lợi cho công ty.'),
('XLV_2018_consolidated', 'XLV', 2018, 'consolidated', 'Công ty có giao dịch tạm ứng với các thành viên Ban điều hành, tuy nhiên số tiền không lớn và đã được hoàn trả, rủi ro thấp.', 'Công ty đã trả hết nợ ngắn hạn và không có nợ dài hạn, áp lực nợ vay thấp.', 'Tồn kho bao gồm chi phí sản xuất kinh doanh dở dang lớn (31.7 tỷ VND), cần giám sát tiến độ dự án xây lắp.', 3, 'Công ty có tình hình tài chính ổn định với tỷ suất lợi nhuận gộp thấp (khoảng 6.3%), không có nợ vay, nhưng lợi nhuận chủ yếu đến từ thu nhập khác (ví dụ: hoàn nhập dự phòng bảo hành). Triển vọng phụ thuộc vào hoạt động xây lắp và dịch vụ quản lý bất động sản.'),
('XDH_2023_consolidated', 'XDH', 2023, 'consolidated', 'Giao dịch với cổ đông lớn UDIC và thành viên HĐQT Trần Hồng Tâm, chủ yếu là phải thu và phải trả, không có lãi suất hoặc tài sản thế chấp bất thường. Rủi ro ở mức trung bình do giá trị giao dịch lớn nhưng không phức tạp.', 'Khoản vay dài hạn 22,968 tỷ VND không có lãi suất và không kỳ hạn, không có tài sản thế chấp, áp lực nợ thấp. Tuy nhiên, nợ ngắn hạn chủ yếu là phải trả người bán và phải trả khác, thanh khoản có thể bị ảnh hưởng.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang cho các dự án bất động sản, giá trị lớn (252,669 tỷ VND). Rủi ro ứ đọng nếu dự án chậm tiến độ hoặc khó bán.', 5, 'Doanh nghiệp có biên lợi nhuận gộp khoảng 12%, nhưng doanh thu và lợi nhuận giảm mạnh so với năm trước. Nợ vay không áp lực, nhưng tồn kho bất động sản dở dang cao. Dòng tiền hoạt động kinh doanh âm, khả năng thanh toán ngắn hạn cần theo dõi. Điểm rủi ro quản trị trung bình, cần đánh giá thêm về tiến độ dự án và hiệu quả quản lý.'),
('XDH_2024_consolidated', 'XDH', 2024, 'consolidated', 'Công ty có giao dịch lớn với cổ đông lớn là Tổng Công ty UDIC, bao gồm phải thu và phải trả, có nguy cơ giao dịch không theo giá thị trường. Cần theo dõi tính minh bạch và công bằng.', 'Nợ vay dài hạn không lãi suất, không kỳ hạn, không thế chấp, áp lực nợ thấp. Tuy nhiên, công ty có nhiều khoản phải trả khác, nhưng không phải nợ vay, nên rủi ro nợ vay thấp.', 'Hàng tồn kho bao gồm nguyên vật liệu có dự phòng giảm giá cao, cho thấy rủi ro tồn kho lỗi thời. Chi phí dở dang liên quan đến nhiều dự án bất động sản, có nguy cơ bị ứ đọng nếu thị trường bất động sản suy giảm.', 5, 'Công ty có lợi nhuận gộp tăng so với năm trước, nhưng doanh thu giảm. Dòng tiền từ hoạt động kinh doanh âm, cho thấy khó khăn trong thu tiền. Tuy nhiên, công ty có tài sản lớn và nợ vay thấp. Triển vọng phụ thuộc vào thị trường bất động sản và kết quả vụ kiện với Công ty Cầu Đường.'),
('XDH_2022_consolidated', 'XDH', 2022, 'consolidated', 'Giao dịch với bên liên quan chính (UDIC) có số dư lớn (hơn 28 tỷ VND phải trả và 11,5 tỷ VND phải thu), nhưng không có thông tin về lãi suất hay điều kiện bất thường. Rủi ro ở mức trung bình do quy mô giao dịch đáng kể nhưng chưa phát hiện dấu hiệu bất lợi.', 'Nợ dài hạn chủ yếu từ một đối tác (Vạn Xuân) với khoản vay không lãi suất, không kỳ hạn và không có tài sản thế chấp, tạo ra rủi ro thanh khoản thấp. Nợ ngắn hạn tập trung vào nhiều nhà cung cấp với tổng giá trị lớn, nhưng Công ty có đủ tiền và tương đương tiền (148 tỷ VND) để bù đắp, cho thấy khả năng thanh toán tốt.', 'Hàng tồn kho bao gồm nguyên vật liệu đã trích lập dự phòng 1,89 tỷ VND và chi phí sản xuất kinh doanh dở dang lớn (214,9 tỷ VND). Các dự án xây dựng dở dang (như CT02B, A1 Yên Hòa) có thể bị ứ đọng nếu tiến độ thi công chậm, nhưng Công ty đã kết chuyển dự án Yên Hòa vào giá vốn, giảm rủi ro tồn đọng.', 5, 'Công ty có vị thế tài chính ổn định với doanh thu thuần 378 tỷ VND và lợi nhuận sau thuế 73,5 tỷ VND trong năm 2022. Tỷ suất lợi nhuận gộp khoảng 31,9% cho thấy hiệu quả kinh doanh tốt. Nợ vay không áp lực lớn, nhưng dòng tiền hoạt động kinh doanh âm (-21,8 tỷ VND) do chi phí đầu tư và trả cổ tức. Công ty có kế hoạch tăng vốn qua cổ tức cổ phiếu, phản ánh triển vọng tăng trưởng. Tuy nhiên, rủi ro quản trị ở mức trung bình do giao dịch với bên liên quan và điều chỉnh hồi tố báo cáo trước.'),
('XDH_2021_consolidated', 'XDH', 2021, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với bên liên quan đáng chú ý: (1) Giao dịch lớn với cổ đông UDIC (sở hữu ~43% vốn) với tổng số dư phải thu 12,6 tỷ, trả trước 1,1 tỷ, phải trả 28,6 tỷ; (2) Hợp tác kinh doanh với Công ty TNHH Đất Việt Nam với khoản phải trả 61,3 tỷ đồng (gồm hợp tác xây dựng E2 Yên Hòa và phân chia lợi nhuận); (3) Khoản vay 23 tỷ từ Công ty CP Đầu tư phát triển đô thị Vạn Xuân không lãi suất, không kỳ hạn, không thế chấp - bất thường và có thể là giao dịch không theo giá thị trường; (4) Nhiều khoản phải trả phân chia lợi nhuận liên doanh với các đối tác (Cầu đường Hà Nội 30,5 tỷ, Công ty Liên doanh Hà Nội Bắc Kinh 13,1 tỷ). Mức độ giao dịch bên liên quan phức tạp, chồng chéo, đặc biệt liên quan đến dự án bất động sản Yên Hòa.', 'Doanh nghiệp có cơ cấu nợ tương đối lành mạnh. Nợ vay chỉ gồm khoản vay dài hạn 23 tỷ VND từ Công ty CP Đầu tư phát triển Vạn Xuân không lãi suất và không kỳ hạn - không tạo áp lực trả nợ. Tuy nhiên, nợ ngắn hạn chiếm tỷ trọng lớn (380,3 tỷ) chủ yếu là phải trả khác (223,8 tỷ) trong đó có nhiều khoản liên quan đến hợp tác kinh doanh và phân chia lợi nhuận dự án. Doanh thu chưa thực hiện dài hạn 185,9 tỷ phản ánh tiền thu trước từ khách hàng mua bất động sản - áp lực bàn giao sản phẩm trong tương lai.', 'Hàng tồn kho lớn 248,1 tỷ VND, trong đó chi phí sản xuất kinh doanh dở dang chiếm 194,2 tỷ (78%) bao gồm nhiều dự án xây dựng dở dang. Dự án Khu đô thị mới Yên Hòa có 25,4 tỷ chi phí xây dựng cơ bản dở dang. Công ty không trích lập dự phòng giảm giá hàng tồn kho. Rủi ro ứ đọng tồn kho là đáng kể nếu tiến độ thi công các dự án bị chậm trễ hoặc thị trường bất động sản suy giảm.', 5, 'Công ty có sức khỏe tài chính tổng thể khá tốt với lợi nhuận sau thuế 127,9 tỷ VND, biên lợi nhuận gộp 35,3%, tiền mặt dồi dào 151,8 tỷ VND. Tuy nhiên, công ty có nhiều điểm cần lưu ý: (1) Giao dịch bên liên quan phức tạp với cổ đông lớn UDIC và nhiều đối tác liên doanh trong dự án Yên Hòa; (2) Khoản vay không lãi suất, không kỳ hạn từ công ty được đầu tư vốn có dấu hiệu giao dịch không theo giá thị trường; (3) Hàng tồn kho dở dang lớn 219,6 tỷ VND với nhiều dự án xây dựng; (4) Doanh thu giảm 36% so với năm trước (từ 828 tỷ xuống 529 tỷ). Công ty hoạt động chủ yếu trong lĩnh vực xây dựng và kinh doanh bất động sản, có dự án trọng điểm là Khu đô thị mới Yên Hòa. Triển vọng phụ thuộc lớn vào tiến độ triển khai dự án và khả năng tiêu thụ sản phẩm bất động sản.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('XDH_2020_consolidated', 'XDH', 2020, 'consolidated', 'Công ty có giao dịch với bên liên quan là cổ đông góp vốn, bao gồm các khoản phải thu, người mua trả tiền trước, trả trước cho người bán và phải trả khác. Giá trị các giao dịch này không lớn so với tổng tài sản, nhưng cần theo dõi để đảm bảo tính công bằng và minh bạch.', 'Nợ vay dài hạn chỉ có một khoản từ Công ty Cổ phần Đầu tư phát triển đô thị Vạn Xuân với lãi suất 0%, không kỳ hạn và không có tài sản thế chấp, cho thấy áp lực nợ thấp nhưng cần kiểm tra mục đích sử dụng vốn.', 'Hàng tồn kho bao gồm nguyên liệu, hàng hóa và chi phí sản xuất dở dang. Dự án bất động sản Khu đô thị mới Yên Hòa có giá trị lớn, cần đánh giá tiến độ và khả năng bán hàng để tránh ứ đọng.', 5, 'Công ty có kết quả kinh doanh tích cực trong năm 2020 với lợi nhuận sau thuế tăng mạnh, nhưng dòng tiền từ hoạt động kinh doanh âm, cho thấy thách thức trong quản lý vốn lưu động. Tổng tài sản giảm, nhưng vốn chủ sở hữu tăng nhẹ. Triển vọng đầu tư phụ thuộc vào khả năng hoàn thành các dự án bất động sản và quản lý giao dịch với bên liên quan.'),
('XDH_2019_consolidated', 'XDH', 2019, 'consolidated', 'Giao dịch với bên liên quan là cổ đông góp vốn, số dư không lớn và không có dấu hiệu bất thường.', 'Áp lực nợ vay thấp, chỉ có khoản vay dài hạn không lãi suất và không tài sản thế chấp, không kỳ hạn.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang của các dự án bất động sản, có rủi ro ứ đọng nếu dự án chậm tiến độ hoặc thị trường bất động sản suy giảm.', 3, 'Công ty có tình hình tài chính ổn định với tỷ suất lợi nhuận gộp cao, nợ vay thấp, nhưng hàng tồn kho lớn và chủ yếu liên quan đến bất động sản, cần theo dõi tiến độ dự án. Triển vọng phụ thuộc vào thị trường bất động sản.'),
('XLV_2024_consolidated', 'XLV', 2024, 'consolidated', 'Công ty có phát sinh tạm ứng cho các thành viên HĐQT, Ban Kiểm soát và Ban Tổng Giám đốc với tổng số dư cuối năm khoảng 2,37 tỷ VNĐ. Các khoản tạm ứng này không có bảo đảm, không tính lãi suất. Tuy nhiên, tỷ lệ hoàn ứng cao (đầu năm tổng tạm ứng lớn hơn nhiều). Công ty không giao dịch mua bán hàng hóa/dịch vụ với bên liên quan. Rủi ro ở mức trung bình do có phát sinh tạm ứng cá nhân cho ban lãnh đạo.', 'Tại ngày lập BCTC, số dư vay và nợ thuê tài chính ngắn hạn và dài hạn đều bằng 0. Công ty không có nợ vay ngân hàng tại thời điểm cuối năm. Tuy nhiên, từ lưu chuyển tiền tệ cho thấy trong năm công ty đã phát sinh vay và trả nợ vay theo chu kỳ (vay 27.6 tỷ, trả 27.6 tỷ) phục vụ nhu cầu vốn lưu động. Công ty đã thế chấp tài sản cố định (xe ô tô nguyên giá 3 tỷ) và quyền sử dụng đất tại VietinBank và BIDV cho các khoản vay đã tất toán. Rủi ro nợ vay thấp.', 'Hàng tồn kho tăng mạnh từ 14,1 tỷ lên 38,5 tỷ VNĐ (tăng 172%), chủ yếu do chi phí sản xuất kinh doanh dở dang tăng từ 11,6 tỷ lên 37,3 tỷ VNĐ. Dự án trọng điểm Đường dây 500kV mạch 3 chiếm tỷ trọng lớn (19,4 tỷ) trong tồn kho dở dang và đã đóng góp doanh thu 322 tỷ đồng. Công ty không trích lập dự phòng giảm giá hàng tồn kho. Rủi ro tồn kho ở mức trung bình - thấp do các công trình đều là dự án điện trọng điểm quốc gia có chủ đầu tư là EVN.', 4, 'Công ty CP Xây lắp và Dịch vụ Sông Đà ghi nhận kết quả kinh doanh tăng trưởng mạnh trong năm 2024: doanh thu thuần đạt 464,5 tỷ VNĐ (tăng 3,1 lần so với năm trước), lợi nhuận sau thuế đạt 9,78 tỷ VNĐ (tăng 3,4 lần). Tăng trưởng chủ yếu đến từ việc hoàn thành bàn giao trên 80% giá trị hợp đồng Đường dây 500kV mạch 3. Lợi nhuận gộp biên đạt 6,43% - mức hợp lý cho ngành xây lắp điện. Công ty không có nợ vay tại thời điểm cuối năm, dòng tiền hoạt động kinh doanh dương 13 tỷ. Tuy nhiên, công ty phụ thuộc lớn vào một dự án trọng điểm (đóng góp ~69% doanh thu xây lắp). Ban lãnh đạo có phát sinh khoản tạm ứng cá nhân nhưng đã được hoàn ứng phần lớn. Công ty được kiểm toán bởi A&C (Baker Tilly) với ý kiến chấp nhận toàn phần.'),
('X77_2025_consolidated', 'X77', 2025, 'consolidated', 'Công ty có giao dịch bán hàng chủ yếu với công ty mẹ Fujisan và vay vốn từ ban lãnh đạo không lãi suất, có thể có xung đột lợi ích.', 'Nợ vay đã quá hạn thanh toán, tài sản thế chấp đang bị thanh lý, nợ ngắn hạn vượt tài sản ngắn hạn, lỗ lũy kế vượt vốn chủ sở hữu, nguy cơ phá sản cao.', 'Hàng tồn kho chưa được đánh giá giá trị thuần có thể thực hiện được, có thể bị giảm giá.', 9, 'Tình hình tài chính của công ty rất yếu, khả năng hoạt động liên tục bị nghi ngờ. Công ty đang lỗ nặng và nợ quá hạn, phụ thuộc vào sự hỗ trợ từ cổ đông và chủ nợ.'),
('XDH_2018_consolidated', 'XDH', 2018, 'consolidated', 'Công ty có giao dịch với các bên liên quan bao gồm cổ đông lớn và đối tác hợp tác kinh doanh. Giao dịch chủ yếu là trả trước và hợp tác đầu tư, giá trị đáng kể nhưng được ghi nhận rõ ràng trong thuyết minh, không có dấu hiệu bất thường hay lạm dụng.', 'Công ty chỉ có một khoản vay dài hạn không lãi suất, không kỳ hạn và không có tài sản thế chấp từ Công ty Cổ phần Đầu tư Phát triển đô thị Vạn Xuân. Áp lực nợ vay thấp, khả năng thanh toán không bị đe dọa.', 'Công ty không có hàng tồn kho vật chất (nguyên liệu, thành phẩm). Tồn kho chính là bất động sản đầu tư, đã khấu hao giảm giá trị, không có dự án dở dang ứ đọng.', 3, 'Công ty có kết quả kinh doanh tích cực năm 2018 với doanh thu và lợi nhuận tăng mạnh, chủ yếu từ hoạt động chuyển nhượng bất động sản. Tình hình tài chính ổn định, nợ vay thấp, lợi nhuận sau thuế đạt 197 tỷ VNĐ. Tuy nhiên, cần lưu ý các điều chỉnh hồi tố do thanh tra thuế và giá trị hợp lý của bất động sản đầu tư chưa được xác định. Triển vọng phụ thuộc vào thị trường bất động sản.'),
('X77_2024_consolidated', 'X77', 2024, 'consolidated', 'Rủi ro cao. Doanh thu bán hàng gần như hoàn toàn phụ thuộc vào công ty mẹ (Công ty CP FUJISAN Việt Nam) với tỷ trọng 98.8%. Cho vay cá nhân không lãi suất và không có tài sản đảm bảo cho ban lãnh đạo (Tổng giám đốc 850 triệu, Chủ tịch HĐQT 200 triệu) trong khi công ty đang lỗ nặng và thiếu vốn lưu động.', 'Rủi ro rất cao. Tổng nợ vay ngắn hạn và dài hạn quá hạn thanh toán, tài sản thế chấp đang bị ngân hàng thanh lý, phát mại. Nợ ngắn hạn vượt tài sản ngắn hạn hơn 195 tỷ đồng. Công ty đã không ghi nhận đầy đủ chi phí lãi vay phát sinh trong năm (13.515.411.253 đồng) và nợ cũ (85.456.770.039 đồng).', 'Rủi ro cao. Hàng tồn kho nguyên liệu 2,9 tỷ đồng không có dự phòng giảm giá, kiểm toán viên không xác định được tính hiện hữu và giá trị. Công ty đã xử lý lỗ tồn kho 262 triệu trong năm nhưng chưa đánh giá đầy đủ giá trị thuần có thể thực hiện được.', 8, 'Công ty trong tình trạng tài chính rất nghiêm trọng: lỗ lũy kế vượt vốn chủ sở hữu 191 tỷ đồng, nợ ngắn hạn vượt tài sản ngắn hạn 195 tỷ đồng, nợ ngân hàng quá hạn thanh toán, tài sản bị phát mại. Doanh thu phụ thuộc hoàn toàn vào công ty mẹ. Ban lãnh đạo cho vay cá nhân không lãi suất từ nguồn vốn công ty. Khả năng hoạt động liên tục bị nghi ngờ nặng nề.'),
('X77_2023_consolidated', 'X77', 2023, 'consolidated', 'Doanh thu bán hàng phụ thuộc gần như hoàn toàn vào Công ty mẹ FUJISAN Việt Nam (1.653/1.692 tỷ đồng, chiếm ~97,8%). Công ty có khoản vay ngắn hạn từ Tổng Giám đốc Nguyễn Thúy Phương 700 triệu đồng. Phải trả ngắn hạn khác bao gồm khoản lớn với Tổng Công ty Thành An (40,7 tỷ - khoản cấp vốn lưu động) và ông Nguyễn Bá Uyền (10,5 tỷ - phát sinh từ việc ngân hàng thu nợ từ tài sản bên thứ ba). Rủi ro giao dịch bên liên quan ở mức rất cao do phụ thuộc doanh thu và cấu trúc nợ nội bộ phức tạp.', 'Nợ vay ngắn hạn trên bảng cân đối kế toán 86,3 tỷ lớn gấp gần 10 lần tổng tài sản 8,7 tỷ. Tất cả khoản vay ngân hàng BIDV Hà Nam (cả ngắn hạn 25,8 tỷ và dài hạn tái phân loại 58,3 tỷ) đều đã quá hạn thanh toán. Tài sản đảm bảo đang bị ngân hàng thanh lý, phát mại. Nợ ngắn hạn vượt tài sản ngắn hạn 196,7 tỷ. Công ty đã bị cưỡng chế hóa đơn. Lãi vay chưa ghi nhận theo kiểm toán là 10,2 tỷ năm 2023 và 75,2 tỷ đầu kỳ. Áp lực nợ vay cực kỳ nghiêm trọng.', 'Hàng tồn kho nguyên liệu, vật liệu trị giá 3,16 tỷ chưa được đánh giá giá trị thuần có thể thực hiện được. Kiểm toán viên không tham gia kiểm kê tại ngày 31/12/2023, không thể xác định tính hiện hữu của khoản mục này. Không có dự phòng giảm giá hàng tồn kho.', 9, 'Công ty Cổ phần Thành An 77 đang trong tình trạng tài chính cực kỳ nghiêm trọng: lỗ lũy kế 205,2 tỷ vượt xa vốn điều lệ 13,4 tỷ; nợ ngắn hạn vượt tài sản ngắn hạn 196,7 tỷ; tất cả nợ vay ngân hàng đều quá hạn và tài sản thế chấp bị phát mại. Doanh thu gần như phụ thuộc hoàn toàn vào công ty mẹ FUJISAN. Công ty bị cưỡng chế hóa đơn, phạt thuế vi phạm hành chính. Kiểm toán viên đưa ý kiến ngoại trừ về hàng tồn kho chưa kiểm kê, lãi vay chưa ghi nhận tổng cộng 85,5 tỷ. Công ty hiện chỉ có 48,9 triệu tiền mặt và 12 nhân viên. Rủi ro đầu tư cực kỳ cao, nguy cơ mất toàn bộ vốn rất lớn.'),
('X77_2020_consolidated', 'X77', 2020, 'consolidated', 'Công ty có giao dịch với công ty mẹ FUJISAN, bao gồm bán hàng và vay ngắn hạn. Các giao dịch này có thể không được thực hiện trên cơ sở thị trường do mối quan hệ liên kết, tiềm ẩn rủi ro về giá cả hoặc điều kiện thanh toán bất lợi cho công ty.', 'Công ty có nợ vay lớn với tổng nợ ngắn hạn và dài hạn khoảng 99 tỷ đồng, vượt quá tài sản ngắn hạn. Công ty đang trong quá trình tái cơ cấu nợ với ngân hàng và nợ ngắn hạn lớn hơn tài sản ngắn hạn 147 tỷ đồng, cho thấy áp lực nợ vay rất cao và rủi ro vỡ nợ.', 'Kiểm toán viên đã chỉ ra phương pháp tính giá trị xuất kho vật tư không phù hợp từ năm 2016, làm ảnh hưởng đến giá trị hàng tồn kho. Hàng tồn kho có thể bị đánh giá cao hơn giá trị thực, và không có dự phòng giảm giá được trích lập, tạo rủi ro giảm giá trong tương lai.', 8, 'Công ty đang gặp khó khăn nghiêm trọng về tài chính với lỗ lũy kế lớn, nợ ngắn hạn vượt quá tài sản ngắn hạn, và các hoạt động chính đã ngừng. Tuy nhiên, công ty đang trong quá trình tái cơ cấu dưới cổ đông mới là Công ty Cổ phần FUJISAN Việt Nam. Triển vọng phụ thuộc vào khả năng thu hồi công nợ và tái cơ cấu nợ thành công.'),
('X77_2019_consolidated', 'X77', 2019, 'consolidated', 'Tồn tại giao dịch với bên liên quan (XN Xây dựng 51 - Cty CP ĐT&XL Thành An 665) với giá trị phải thu 1.965.800.000 VND. Không có thông tin về lãi suất hay tài sản đảm bảo cho giao dịch này.', 'Nợ vay ngắn hạn và dài hạn tổng cộng khoảng 100.221.435.454 VND, chiếm tỷ trọng lớn trong tổng nguồn vốn (hơn 60%). Phần lớn tài sản cố định đã được thế chấp cho khoản vay tại BIDV. Công ty đang đàm phán cơ cấu lại nợ và xin giảm/xóa lãi vay, phản ánh áp lực nợ vay rất lớn và rủi ro thanh khoản cao.', 'Hàng tồn kho (nguyên liệu và thành phẩm) trị giá 4.644.459.970 VND. Kiểm toán viên từ chối đưa ra ý kiến về tính hiện hữu và giá trị của hàng tồn kho do công ty không thực hiện nhập xuất trong năm 2019 và phương pháp tính giá từ năm 2016 chưa phù hợp, tiềm ẩn rủi ro giá trị ghi sổ không phản ánh hợp lý.', 8, 'Tình hình tài chính của công ty rất nghiêm trọng. Doanh thu hoạt động kinh doanh thấp hơn nhiều so với giá vốn, dẫn đến lỗ gộp gần 7,8 tỷ VND. Lỗ lũy kế đã vượt quá vốn chủ sở hữu, nợ ngắn hạn lớn hơn tài sản ngắn hạn 149 tỷ VND, đặt công ty trước nguy cơ mất khả năng thanh toán. Công ty đang trong quá trình tái cơ cấu với cổ đông mới (Fujisan) và đàm phán với ngân hàng về nợ vay. Rủi ro đầu tư là cực kỳ cao.'),
('X77_2021_consolidated', 'X77', 2021, 'consolidated', 'Giao dịch với công ty mẹ Công ty Cổ phần FUJISAN Việt Nam bao gồm bán hàng và cho vay, nhưng không có thông tin về giao dịch bất thường. Tuy nhiên, công ty đang trong tình trạng tài chính khó khăn, nên rủi ro liên quan đến bên liên quan có thể tăng.', 'Nợ vay cao, nợ ngắn hạn vượt quá tài sản ngắn hạn 146,4 tỷ đồng, lỗ lũy kế vượt vốn chủ sở hữu hơn 14 lần, khả năng thanh toán thấp. Công ty đang đàm phán tái cơ cấu nợ với ngân hàng.', 'Hàng tồn kho có giá trị 3,19 tỷ đồng, nhưng theo kiểm toán, phương pháp tính giá trị xuất kho chưa phù hợp từ năm 2016, và kiểm toán viên không thể đánh giá giá trị thuần có thể thực hiện được.', 8, 'Công ty đang trong tình trạng tài chính nghiêm trọng với lỗ lũy kế lớn, nợ cao, và ngừng hoạt động chính. Tuy nhiên, cổ đông mới đang tái cơ cấu, nhưng khả năng hoạt động liên tục còn nghi ngờ.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('X77_2018_consolidated', 'X77', 2018, 'consolidated', 'Công ty có các giao dịch với bên liên quan, bao gồm phải thu từ XN Xây dựng 51 và phải trả cho Tổng Công ty Thành An. Điều này có thể gây rủi ro về khả năng thu hồi công nợ và tính công bằng trong giao dịch.', 'Công ty có nợ vay và phải trả lớn, vượt quá tài sản ngắn hạn. Áp lực nợ cao, khả năng thanh toán thấp, và công ty đang đàm phán tái cơ cấu nợ với ngân hàng.', 'Hàng tồn kho bao gồm nguyên vật liệu và thành phẩm, nhưng giá trị có thể không phản ánh đúng do thực tế không nhập xuất trong năm và phương pháp tính giá không phù hợp, theo báo cáo kiểm toán.', 8, 'Công ty đang trong tình trạng tài chính khó khăn, với vốn chủ sở hữu âm, lỗ lũy kế lớn, và nợ ngắn hạn vượt tài sản ngắn hạn. Việc tái cơ cấu bởi cổ đông mới Fujisan Việt Nam là hy vọng duy nhất, nhưng rủi ro vẫn cao.'),
('X77_2015_consolidated', 'X77', 2015, 'consolidated', 'Công ty có giao dịch với các bên liên quan bao gồm Tổng Công ty Thành An và các đơn vị trực thuộc. Các giao dịch chủ yếu là mua bán hàng hóa và cho vay nội bộ, không có dấu hiệu bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Áp lực nợ vay cao với tổng nợ vay khoảng 109.796.009.049 VND, vượt quá vốn chủ sở hữu âm. Công ty lỗ lũy kế, phụ thuộc vào vay nợ và hỗ trợ tài chính từ chủ đầu tư. Tài sản thế chấp không được nêu rõ, nhưng khả năng thanh toán thấp.', 'Tồn kho chủ yếu là nguyên vật liệu và thành phẩm, không có dự án bất động sản. Tuy nhiên, doanh nghiệp hoạt động thua lỗ liên tục, có nguy cơ tồn kho chậm luân chuyển hoặc mất giá.', 7, 'Tình hình tài chính yếu kém với lỗ lũy kế lớn, vốn chủ sở hữu âm, và phụ thuộc vào nợ vay. Kiểm toán đưa ra ý kiến ngoại trừ do lo ngại về tính liên tục hoạt động. Doanh nghiệp cần cải thiện hiệu quả kinh doanh và quản lý nợ để giảm rủi ro.'),
('XMC_2015_consolidated', 'XMC', 2015, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là mua bán, dịch vụ và cho vay nội bộ giữa công ty mẹ và các công ty con, liên kết. Giá trị giao dịch không lớn so với quy mô tài sản và doanh thu. Không có bằng chứng về giao dịch bất thường như cho vay không lãi suất hay chênh lệch giá lớn đáng ngờ.', 'Áp lực nợ vay rất cao. Tổng nợ vay (ngắn hạn và dài hạn) cuối năm đạt 1.644 tỷ VNĐ, tăng mạnh so với đầu năm. Nợ ngắn hạn chiếm tỷ trọng lớn (1.263 tỷ VNĐ), gây áp lực thanh khoản tức thời. Các khoản vay được đảm bảo bằng tài sản là bất động sản và quyền dự án, cho thấy công ty dựa nhiều vào đòn bẩy tài chính và tài sản thế chấp.', 'Rủi ro tồn kho dở dang cao. Hàng tồn kho tăng mạnh chủ yếu do chi phí sản xuất kinh doanh dở dang (885 tỷ VNĐ) và nhiều dự án xây dựng cơ bản dở dang (tổng cộng 18,8 tỷ VNĐ). Các dự án nhà ở chung cư và hạ tầng vẫn đang trong giai đoạn triển khai, tiềm ẩn rủi ro về tiến độ, giá thành và khả năng tiêu thụ.', 6, 'Công ty có tăng trưởng doanh thu nhưng lợi nhuận sau thuế giảm. Cơ cấu tài chính mất cân đối nghiêm trọng với nợ vay cao, đặc biệt nợ ngắn hạn, trong khi dòng tiền hoạt động kinh doanh âm. Công ty đang trong giai đoạn mở rộng đầu tư mạnh vào tài sản dở dang và dự án, đòi hỏi nguồn vốn lớn. Triển vọng phụ thuộc vào khả năng huy động vốn, hoàn thiện và tiêu thụ các dự án bất động sản, xây lắp trong bối cảnh thị trường có nhiều biến động.'),
('YBC_2025_consolidated', 'YBC', 2025, 'consolidated', 'Công ty có một số giao dịch với bên liên quan đáng lưu ý: (1) Các khoản vay dài hạn từ cá nhân liên quan đến ban lãnh đạo như ông Vũ Xuân Nguyên (Chủ tịch HĐQT) cho vay 10,8 tỷ VND, ông Lã Văn Tâm cho vay 23,77 tỷ VND theo khế ước 10-20 năm với lãi suất theo thỏa thuận, không có tài sản đảm bảo riêng. (2) Ông Nguyễn Ngọc Phương cho vay ngắn hạn 58,86 tỷ VND bổ sung vốn lưu động với lãi suất thỏa thuận. (3) Công ty có khoản phải trả Clinker 1,76 tỷ cho Công ty Cổ phần Xi măng Yên Bình - nơi Công ty góp vốn 1,67%. (4) Các khoản phải trả người bán dài hạn với các đối tác có mối quan hệ kinh doanh lâu dài như Công ty TNHH SXDV và TM Quỳnh Anh (14 tỷ), Công ty TNHH Một thành viên Tiến Sa (15 tỷ). Tổng thể, các giao dịch với bên liên quan không bất thường nghiêm trọng nhưng cần theo dõi chặt chẽ các khoản cho vay cá nhân.', 'Áp lực nợ vay của Công ty là RẤT LỚN. Tại ngày 31/12/2025, nợ ngắn hạn vượt quá tài sản ngắn hạn 105,5 tỷ đồng, tỷ lệ nợ phải trả/tổng tài sản đạt 89%. Tổng vay và nợ thuê tài chính là 679,16 tỷ VND, trong đó ngắn hạn 353,68 tỷ và dài hạn 325,48 tỷ. Chi phí lãi vay năm 2025 là 52,09 tỷ VND, tăng 25,3% so với năm trước (41,51 tỷ), chiếm tỷ trọng lớn trong cơ cấu chi phí. Công ty sử dụng HẦU HẾT tài sản cố định có nguyên giá 873,8 tỷ VND (giá trị còn lại 515,4 tỷ) làm tài sản thế chấp cho các khoản vay tại BIDV Yên Bái và Agribank. Tuy nhiên, Công ty vẫn duy trì được quan hệ tín dụng tốt với hai ngân hàng lớn và dòng tiền từ hoạt động SXKD vẫn dương.', 'Hàng tồn kho tăng 14,4% so với đầu năm (từ 268 tỷ lên 306,65 tỷ VND), phản ánh hoạt động sản xuất kinh doanh mở rộng. Đáng lưu ý, chi phí xây dựng cơ bản dở dang tăng MẠNH 248% từ 24,36 tỷ lên 84,95 tỷ VND, cho thấy Công ty đang đầu tư rất lớn vào nâng cấp mở rộng sản xuất (cải tạo lò nung Clinker, dây chuyền nghiền thủy lực, tận dụng nhiệt khí thải phát điện...). Các dự án xây dựng dở dang này chưa được tính khấu hao, tạo áp lực khấu hao lớn trong tương lai khi hoàn thành. Công ty không trích lập dự phòng giảm giá hàng tồn kho, điều này hợp lý nếu giá trị thuần có thể thực hiện không thấp hơn giá gốc.', 6, 'Công ty Cổ phần Xi măng và Khoáng sản Yên Bái đang trong giai đoạn đầu tư mở rộng sản xuất mạnh mẽ, với kết quả kinh doanh vẫn có lãi (lợi nhuận sau thuế 7,61 tỷ VND năm 2025, giảm 47% so với năm trước 14,45 tỷ do chi phí lãi vay tăng mạnh). Doanh thu thuần đạt 880,4 tỷ VND, tăng 4,3%. Tuy nhiên, Công ty đối mặt với rủi ro thanh khoản nghiêm trọng khi nợ ngắn hạn vượt quá tài sản ngắn hạn 105,5 tỷ đồng. Chi phí lãi vay tăng vọt 25,3% phản ánh gánh nặng tài chính từ hoạt động vay nợ đầu tư. Điểm tích cực là Công ty vẫn được các ngân hàng lớn (BIDV, Agribank) duy trì cấp tín dụng và có chiến lược đầu tư nâng cấp thiết bị rõ ràng. Công ty cam kết BCTC được lập trên giả định hoạt động liên tục và kiểm toán viên cũng đồng thuận với giả định này.'),
('X26_2023_consolidated', 'X26', 2023, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, đặc biệt là Tổng cục Hậu cần - Bộ Quốc phòng, chiếm phần lớn doanh thu. Giao dịch dường như dựa trên điều kiện thị trường và không có dấu hiệu bất thường, nhưng sự phụ thuộc lớn có thể tạo rủi ro nếu có thay đổi trong quan hệ.', 'Nợ vay ngắn hạn vừa phải với lãi suất hợp lý và có tài sản đảm bảo. Áp lực nợ vay thấp, khả năng thanh toán tốt.', 'Hàng tồn kho đa dạng, có dự phòng giảm giá nhưng không đáng kể. Rủi ro tồn kho thấp, không có dấu hiệu ứ đọng.', 5, 'Công ty có tình hình tài chính ổn định, lợi nhuận đều đặn, nợ vay kiểm soát tốt. Tuy nhiên, sự phụ thuộc vào các bên liên quan và vấn đề khấu hao tài sản cố định là những điểm cần theo dõi. Triển vọng đầu tư trung bình.'),
('X26_2024_consolidated', 'X26', 2024, 'consolidated', 'Công ty có giao dịch mua bán lớn với các bên liên quan thuộc Bộ Quốc phòng, nhưng các giao dịch này có vẻ bình thường và không có dấu hiệu bất thường rõ ràng về giá cả hay điều kiện thanh toán.', 'Nợ vay ngắn hạn với lãi suất thấp và thời hạn ngắn, áp lực nợ không lớn. Tuy nhiên, một số khoản vay không có tài sản đảm bảo, nhưng Công ty có đủ tài sản ngắn hạn để thanh toán.', 'Hàng tồn kho bao gồm nguyên liệu, thành phẩm và chi phí dở dang, không có dự phòng giảm giá trong năm nay, cho thấy tồn kho được quản lý tốt, nhưng cần theo dõi khả năng tiêu thụ sản phẩm.', 5, 'Công ty có sự tăng trưởng mạnh về doanh thu và lợi nhuận, tài sản ổn định, nợ vay không đáng lo ngại. Tuy nhiên, sự phụ thuộc lớn vào khách hàng chính là Bộ Quốc phòng có thể tạo rủi ro nếu có thay đổi trong chính sách mua sắm. Triển vọng đầu tư ở mức trung bình.'),
('X26_2021_consolidated', 'X26', 2021, 'consolidated', 'Công ty có giao dịch lớn với các bên liên quan thuộc Tổng Cục Hậu cần - Bộ Quốc phòng, đặc biệt doanh thu bán hàng tập trung vào Cục Quân nhu. Có khoản phải trả khác lớn cho Phòng Tài chính - Tổng Cục Hậu cần (72,64 tỷ VND) là tiền ứng trước các hợp đồng quốc phòng, chưa có hợp đồng thuê đất. Điều này tạo rủi ro phụ thuộc và thiếu minh bạch trong giao dịch với bên liên quan.', 'Công ty không có nợ vay cuối kỳ (đã trả hết), áp lực nợ thấp. Tuy nhiên, phải trả ngắn hạn khác tăng mạnh (160,4 tỷ VND) bao gồm các khoản phải trả cho bên liên quan, cần theo dõi khả năng thanh toán.', 'Hàng tồn kho tăng mạnh từ 134 tỷ lên 210 tỷ VND, chủ yếu ở thành phẩm và nguyên liệu. Hàng tồn kho không trích lập dự phòng, cần đánh giá rủi ro ứ đọng và giảm giá.', 6, 'Công ty có doanh thu tăng 20%, lợi nhuận sau thuế giảm nhẹ 5%. Tuy nhiên, dòng tiền hoạt động kinh doanh âm (-91,9 tỷ VND) do tăng mạnh phải thu và tồn kho. Kiểm toán ngoại trừ về việc chưa ghi nhận tài sản cố định từ dự án di dời, ảnh hưởng đến tính trung thực của báo cáo. Sức khỏe tài chính ở mức trung bình, triển vọng phụ thuộc vào việc xử lý tài sản và kiểm soát tồn kho.'),
('X26_2018_consolidated', 'X26', 2018, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan thuộc Bộ Quốc phòng, bao gồm bán hàng, phải thu và phải trả. Các khoản công nợ phải thu từ các bên liên quan không có bảo đảm và được thanh toán bằng tiền, không có dự phòng phải thu khó đòi. Mặc dù có mối quan hệ mật thiết với Bộ Quốc phòng, không có giao dịch bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty không có nợ vay ngân hàng (cả ngắn hạn và dài hạn đều bằng 0). Nợ chủ yếu là phải trả người bán, người lao động và các khoản phải trả khác. Tiền mặt giảm mạnh từ 423 tỷ xuống 193 tỷ VND, cho thấy áp lực thanh toán ngắn hạn tăng. Hàng tồn kho tăng mạnh có thể ảnh hưởng đến khả năng thanh toán.', 'Hàng tồn kho tăng mạnh từ 110,6 tỷ lên 174,1 tỷ VND (tăng 57%), chủ yếu do thành phẩm tăng từ 62,6 tỷ lên 87,4 tỷ VND và nguyên liệu tăng từ 37,4 tỷ lên 52,9 tỷ VND. Chi phí sản xuất dở dang cũng tăng từ 8,7 tỷ lên 14,5 tỷ VND. Điều này cho thấy có thể có rủi ro ứ đọng tồn kho nếu nhu cầu thị trường giảm.', 5, 'Công ty Cổ phần 26 có kết quả kinh doanh giảm so với năm trước: lợi nhuận sau thuế giảm từ 21,6 tỷ xuống 17,1 tỷ VND. Công ty không có nợ vay ngân hàng nhưng có áp lực thanh toán phải trả tăng cao. Hàng tồn kho tăng mạnh 57% có thể là dấu hiệu ứ đọng. Tiền mặt giảm mạnh 54% từ 423 tỷ xuống 193 tỷ VND. Công ty có mối quan hệ mật thiết với Bộ Quốc phòng, tạo ra nguồn khách hàng ổn định nhưng cũng phụ thuộc vào một nhóm khách hàng lớn. Dự án di dời nhà máy chưa được quyết toán, ảnh hưởng đến việc ghi nhận tài sản cố định. Triển vọng trung bình trong ngắn hạn.'),
('X26_2020_consolidated', 'X26', 2020, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là bán hàng và mua hàng hóa, không có giao dịch bất thường nào được ghi nhận.', 'Không có khoản vay nợ, nhưng nợ phải trả ngắn hạn lớn, tuy nhiên công ty có đủ tiền và tương đương tiền để thanh toán.', 'Hàng tồn kho không trích lập dự phòng, nhưng cần theo dõi tồn kho dở dang và thành phẩm.', 5, 'Công ty có kết quả kinh doanh tăng trưởng, không có nợ vay, thanh khoản tốt, nhưng có rủi ro từ giao dịch bên liên quan và tồn kho.'),
('X26_2019_consolidated', 'X26', 2019, 'consolidated', 'Doanh thu của Công ty phụ thuộc lớn vào các đơn vị thuộc Bộ Quốc phòng (chiếm hơn 60% doanh thu). Các giao dịch này có thể bị ảnh hưởng bởi ngân sách nhà nước và có rủi ro về giá cả hoặc thanh toán. Công nợ với các bên liên quan không có bảo đảm.', 'Công ty không có nợ vay ngân hàng. Tuy nhiên, các khoản phải trả người mua trước (chiếm tỷ trọng lớn) và phải trả người bán tạo áp lực về vốn lưu động. Các khoản phải trả ngắn hạn khác bao gồm nhiều khoản nợ lớn với các cơ quan nhà nước.', 'Hàng tồn kho tăng so với đầu năm, đặc biệt thành phẩm và hàng hóa. Có nguy cơ ứ đọng nếu nhu cầu giảm hoặc sản phẩm lỗi thời. Hàng tồn kho không có dự phòng giảm giá.', 7, 'Công ty hoạt động trong lĩnh vực sản xuất công nghiệp, doanh thu tăng nhẹ 2.8%, lợi nhuận sau thuế tăng 4.4%. Tuy nhiên, có vấn đề kiểm toán ngoại trừ do chưa ghi nhận đúng tài sản cố định từ dự án tái định cư. Rủi ro lớn từ phụ thuộc vào khách hàng là các cơ quan nhà nước và giao dịch với bên liên quan. Cơ cấu vốn chủ yếu từ vốn chủ sở hữu, không có nợ vay tài chính.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('X20_2025_consolidated', 'X20', 2025, 'consolidated', 'Doanh nghiệp có giao dịch mua bán lớn với các đơn vị trực thuộc Bộ Quốc Phòng và công ty liên kết, tạo sự phụ thuộc vào hợp đồng chính phủ, có nguy cơ xung đột lợi ích và thiếu minh bạch về giá giao dịch.', 'Nợ vay ở mức thấp với tỷ lệ nợ trên tổng tài sản khoảng 1.75%, lãi suất cố định 12%/năm, áp lực trả nợ thấp nhưng chi phí lãi vay cao so với mặt bằng chung.', 'Hàng tồn kho có dự phòng giảm giá nhưng tỷ lệ dự phòng trên giá gốc không đáng kể (khoảng 1.6% cho nguyên liệu và 1.1% cho thành phẩm), cho thấy rủi ro tồn kho thấp và không có dấu hiệu ứ đọng lớn.', 7, 'Công ty hoạt động trong ngành dệt may với doanh thu giảm nhẹ từ 1,301 tỷ VND xuống 1,115 tỷ VND, lợi nhuận sau thuế giảm từ 45.2 tỷ xuống 34.7 tỷ VND. Nợ vay thấp, tỷ suất lợi nhuận gộp khoảng 17.9%, nhưng chi phí lãi vay cao và phụ thuộc lớn vào các bên liên quan thuộc Bộ Quốc Phòng. Triển vọng tăng trưởng trung bình nếu cải thiện hiệu quả hoạt động và đa dạng hóa khách hàng.'),
('X26_2017_consolidated', 'X26', 2017, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là các đơn vị thuộc Bộ Quốc phòng, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty không có nợ vay ngân hàng, nợ chủ yếu là phải trả thương mại và phải trả khác, áp lực nợ thấp và không có tài sản thế chấp nổi bật.', 'Hàng tồn kho chủ yếu là thành phẩm và nguyên liệu, không có dự phòng giảm giá, rủi ro thấp, không có dự án xây dựng dở dang ứ đọng.', 3, 'Công ty có kết quả kinh doanh tăng trưởng, không có nợ vay, tài sản thanh khoản cao, quản trị ổn định, triển vọng đầu tư tích cực.'),
('X20_2024_consolidated', 'X20', 2024, 'consolidated', 'Công ty có giao dịch mua bán lớn với các đơn vị thuộc Bộ Quốc Phòng, đặc biệt là doanh thu bán hàng chiếm tỷ trọng cao. Điều này tạo ra sự phụ thuộc vào đối tác liên quan, nhưng không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay chênh lệch giá lớn.', 'Nợ vay chủ yếu từ Ngân hàng TMCP Công thương Việt Nam với lãi suất 12%/năm cho dự án đầu tư. Tổng nợ vay khoảng 13,259 tỷ VNĐ so với vốn chủ sở hữu 289,695 tỷ VNĐ, tỷ lệ nợ vay thấp, áp lực nợ không đáng kể.', 'Hàng tồn kho bao gồm nguyên liệu, thành phẩm và chi phí sản xuất dở dang, dự phòng giảm giá giảm so với năm trước, cho thấy quản lý tồn kho cải thiện. Các dự án xây dựng dở dang chủ yếu là phần mềm và cải tạo nhà xưởng, không có dấu hiệu ứ đọng.', 5, 'Công ty ghi nhận tăng trưởng doanh thu 25.8% và lợi nhuận sau thuế tăng 122% so với năm trước, dòng tiền hoạt động kinh doanh dương mạnh. Tuy nhiên, doanh thu phụ thuộc lớn vào các đơn vị quốc phòng. Nợ vay thấp, tài sản thế chấp rõ ràng. Triển vọng tích cực từ dự án đầu tư mới và mở rộng sản xuất.'),
('X20_2023_parent', 'X20', 2023, 'parent', 'Công ty có nhiều giao dịch với các công ty con và bên liên quan thuộc Bộ Quốc Phòng, bao gồm cho vay không lãi suất hoặc lãi suất thấp, mua bán hàng hóa với giá trị lớn. Điều này đặt ra rủi ro về tính minh bạch và công bằng trong giao dịch, có thể ảnh hưởng đến lợi ích của cổ đông thiểu số.', 'Công ty không có nợ vay ngân hàng, tỷ lệ nợ trên vốn chủ sở hữu là 0%, không có áp lực nợ. Tuy nhiên, công ty có các khoản phải trả người bán lớn, nhưng phần lớn là thương mại và có khả năng trả nợ.', 'Hàng tồn kho tăng mạnh so với đầu năm, chủ yếu do nguyên liệu và thành phẩm tăng. Có dự phòng giảm giá hàng tồn kho, nhưng mức dự phòng đã giảm so với đầu năm. Rủi ro tồn kho ở mức trung bình do chu kỳ kinh doanh ngắn.', 5, 'Công ty có tình hình tài chính lành mạnh với tỷ lệ nợ bằng 0, thanh khoản tốt. Tuy nhiên, doanh thu và lợi nhuận giảm so với năm trước, dòng tiền hoạt động kinh doanh âm do tăng mạnh khoản phải thu và hàng tồn kho. Công ty phụ thuộc lớn vào giao dịch với Bộ Quốc Phòng, tạo ra rủi ro tập trung khách hàng. Triển vọng trung hạn ổn định nhưng cần cải thiện hiệu quả quản lý vốn lưu động.'),
('X20_2023_consolidated', 'X20', 2023, 'consolidated', 'Công ty có giao dịch lớn với các bên liên quan thuộc Bộ Quốc Phòng và công ty liên kết. Tổng mua hàng từ bên liên quan chiếm khoảng 4.3% giá vốn hàng bán, bán hàng cho bên liên quan chiếm khoảng 54% doanh thu. Mặc dù không có thông tin về lãi suất ưu đãi hay giao dịch bất thường, nhưng mức độ tập trung cao vào các đơn vị liên quan có thể gây rủi ro về tính công bằng và độc lập trong giao dịch.', 'Công ty không có nợ vay cuối kỳ, tỷ lệ nợ trên vốn chủ sở hữu 0%. Nợ phải trả chủ yếu là phải trả người bán và các khoản khác. Áp lực nợ thấp, khả năng thanh toán tốt.', 'Hàng tồn kho tăng 28% so với đầu năm, chủ yếu do tăng nguyên liệu và thành phẩm. Dự phòng giảm giá tồn kho giảm, cho thấy quản lý tồn kho hiệu quả. Tuy nhiên, cần theo dõi khả năng tiêu thụ.', 5, 'Công ty hoạt động trong ngành dệt may, doanh thu giảm 9.6% so với năm trước, lợi nhuận giảm 8%. Không có nợ vay, thanh khoản tốt. Tuy nhiên, doanh thu phụ thuộc lớn vào một khách hàng là Cục Quân nhu (thuộc Bộ Quốc Phòng). Giao dịch với bên liên quan chiếm tỷ trọng lớn, cần đánh giá thêm về tính độc lập. Triển vọng trung bình.'),
('X20_2021_consolidated', 'X20', 2021, 'consolidated', 'Giao dịch với các bên liên quan chiếm tỷ trọng lớn, đặc biệt là doanh thu từ Cục Quân nhu, cho thấy sự phụ thuộc đáng kể.', 'Áp lực nợ vay giảm so với năm trước, nhưng vẫn có nợ dài hạn với lãi suất biến động.', 'Tồn kho tăng mạnh, đặc biệt là thành phẩm và hàng hóa, cần theo dõi khả năng tiêu thụ.', 6, 'Công ty có tăng trưởng doanh thu nhưng lợi nhuận giảm. Tồn kho và công nợ cần được quản lý chặt chẽ. Triển vọng trung lập.'),
('X20_2022_consolidated', 'X20', 2022, 'consolidated', 'Các giao dịch với các bên liên quan chủ yếu là mua bán hàng hóa và thanh toán cổ tức, không có giao dịch bất thường như cho vay không lãi suất. Các bên liên quan chủ yếu là các đơn vị thuộc Bộ Quốc Phòng, do đó rủi ro thấp.', 'Công ty không có nợ vay tại ngày 31/12/2022, áp lực nợ vay thấp. Tài sản thế chấp trước đây đã được giải chấp.', 'Tồn kho có dự phòng giảm giá, đặc biệt cho nguyên liệu và thành phẩm. Cần theo dõi khả năng tiêu thụ hàng hóa.', 3, 'Công ty có tình hình tài chính khỏe mạnh, không có nợ vay, doanh thu tăng trưởng tốt. Tuy nhiên, tồn kho cao và dự phòng giảm giá có thể ảnh hưởng đến lợi nhuận. Triển vọng kinh doanh phụ thuộc vào hợp đồng quân sự.'),
('X20_2021_parent', 'X20', 2021, 'parent', 'Công ty có giao dịch lớn với các bên liên quan, đặc biệt là doanh thu từ bán hàng và mua hàng với các công ty con và đơn vị thuộc Bộ Quốc phòng, chiếm tỷ trọng cao trong tổng doanh thu. Không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất, nhưng cần lưu ý về tính liên kết và potential for transfer pricing.', 'Công ty không có nợ vay ngân hàng, nợ chủ yếu là phải trả người bán và phải trả khác, áp lực nợ thấp. Tuy nhiên, tài sản thế chấp không rõ ràng, nhưng nợ ngắn hạn có khả năng thanh toán từ hoạt động kinh doanh.', 'Hàng tồn kho có dự phòng giảm giá lớn, đặc biệt là nguyên liệu, vật liệu với dự phòng 10.2 tỷ VNĐ, cho thấy rủi ro tồn kho cao do giá trị giảm.', 6, 'Công ty có tình hình tài chính ổn định với tỷ lệ nợ thấp, nhưng lợi nhuận sau thuế giảm mạnh so với năm trước do chi phí tăng. Tồn kho cần được quản lý chặt chẽ để tránh mất mát. Công ty có mối quan hệ chặt chẽ với Bộ Quốc phòng, tạo nguồn doanh thu ổn định nhưng cũng mang tính phụ thuộc.'),
('X20_2019_consolidated', 'X20', 2019, 'consolidated', 'Công ty có giao dịch với bên liên quan là Công ty cổ phần 199 (công ty liên kết sở hữu 33,4%) với quy mô nhỏ: cho thuê TSCĐ 9,6 triệu và nhận cổ tức 199 triệu. Các giao dịch đã được công khai trong báo cáo. Không phát hiện giao dịch bất thường hay che giấu với bên liên quan.', 'Áp lực nợ vay ngắn hạn đáng kể: cuối kỳ nợ ngắn hạn 84,2 tỷ trong khi tiền mặt chỉ 26,9 tỷ, tỷ lệ nợ/vốn chủ sở hữu là 1,23 lần. Công ty đã giảm nợ ngắn hạn từ 128,2 tỷ xuống 84,2 tỷ và tăng vay dài hạn 10,6 tỷ (trước đó không có nợ dài hạn). Nợ vay chủ yếu từ ngân hàng TMCP Quân đội và BIDV với lãi suất 7.7-8%/năm, tài sản thế chấp không được nêu rõ.', 'Hàng tồn kho giảm mạnh 45% từ 300,9 tỷ xuống 164,5 tỷ (giảm 136,4 tỷ). Chi phí SXKD dở dang giảm từ 136,5 tỷ xuống 32,3 tỷ, cho thấy công ty đã đẩy mạnh tiêu thụ và sản xuất. Dự phòng giảm giá hàng tồn kho chỉ 62,9 triệu (rất nhỏ so với giá trị tồn kho), thành phẩm chiếm tỷ trọng lớn nhất 70,4 tỷ.', 4, 'Năm 2019 doanh thu giảm 13% (từ 1.047,6 tỷ xuống 910,2 tỷ), lợi nhuận sau thuế giảm mạnh 78% (từ 24 tỷ xuống 5,3 tỷ). Công ty đã giảm nợ vay ngắn hạn 44 tỷ và giảm mạnh hàng tồn kho 136 tỷ, cải thiện dòng tiền hoạt động kinh doanh dương 64,5 tỷ. Hoạt động kinh doanh BĐS mới phát sinh doanh thu 70,4 tỷ (chiếm 7.7% doanh thu). Công ty thanh toán cổ tức 17,25 tỷ và phân phối lợi nhuận 6,76 tỷ. Điểm rủi ro trung bình do có công ty liên kết, thay đổi Chủ tịch HĐQT, và dự phòng phải thu khó đòi 4,8 tỷ. Công ty đang trong giai đoạn tái cơ cấu nợ và đa dạng hóa ngành nghề.'),
('X20_2020_consolidated', 'X20', 2020, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là với các đơn vị thuộc Bộ Quốc phòng, quy mô lớn nhưng không có dấu hiệu bất thường.', 'Nợ vay giảm đáng kể so với đầu năm, có tài sản thế chấp, áp lực nợ thấp.', 'Tồn kho tăng, có dự phòng giảm giá, rủi ro tồn kho ở mức trung bình.', 5, 'Công ty có tình hình tài chính ổn định, lợi nhuận tăng, nợ giảm, nhưng phụ thuộc lớn vào khách hàng liên quan.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('X20_2020_parent', 'X20', 2020, 'parent', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan, đặc biệt là mua bán hàng hóa và cho thuê tài sản. Các giao dịch này diễn ra thường xuyên và có giá trị lớn, nhưng không có dấu hiệu bất thường rõ ràng. Tuy nhiên, cần theo dõi vì tỷ lệ giao dịch nội bộ cao.', 'Nợ vay ngắn hạn đã được thanh toán hết, chỉ còn nợ dài hạn nhỏ 800 triệu VNĐ. Áp lực nợ vay thấp, khả năng thanh toán tốt.', 'Hàng tồn kho tăng mạnh so với năm trước, với dự phòng giảm giá tăng đáng kể, cho thấy rủi ro về hàng tồn kho chậm luân chuyển. Cần kiểm soát chặt chẽ hơn.', 4, 'Sức khỏe tài chính của công ty cải thiện trong năm 2020 với lợi nhuận tăng cao, nợ giảm. Tuy nhiên, rủi ro tồn kho và giao dịch bên liên quan cần được giám sát.'),
('X20_2017_consolidated', 'X20', 2017, 'consolidated', 'Giao dịch với Công ty Cổ phần 199 (công ty liên kết sở hữu 33.4%) có giá trị mua hàng lớn (18.7 tỷ VND) so với bán hàng (2.6 tỷ VND). Số dư phải thu giảm mạnh từ 4.55 tỷ về 0, đồng thời phát sinh phải trả 508 triệu. Giao dịch mua bán hàng hóa với công ty liên kết có thể có rủi ro về giá chuyển nhượng, tuy nhiên không có bằng chứng rõ ràng về giao dịch bất thường. Công ty cũng nhận thù lao đáng kể cho HĐQT và BKS (3.74 tỷ VND).', 'Áp lực nợ ngắn hạn rất lớn với 242.96 tỷ VND, trong đó nợ với Cục tài chính Bộ Quốc phòng chiếm 240 tỷ VND (98.8%). Công ty có tỷ lệ nợ phải trả/vốn chủ sở hữu = 2.28x, cho thấy đòn bẩy tài chính cao. Tuy nhiên, dòng tiền hoạt động kinh doanh thuần đạt 79.3 tỷ VND trong năm, đủ khả năng trả nợ ngắn hạn. Rủi ro tập trung vào việc phụ thuộc vào nguồn vốn từ cơ quan nhà nước.', 'Hàng tồn kho tăng mạnh từ 234.2 tỷ lên 269.2 tỷ VND (tăng 15%), trong đó hàng hóa tăng vọt từ 3.85 tỷ lên 41.4 tỷ VND (gấp 10 lần) cho thấy có thể có hàng nhập khẩu chờ bán. Chi phí sản xuất kinh doanh dở dang 127 tỷ VND tăng so với năm trước (94 tỷ). Dự phòng giảm giá hàng tồn kho rất nhỏ chỉ 22 triệu VND so với tổng giá trị 269 tỷ, có thể chưa phản ánh đầy đủ rủi ro. Chi phí xây dựng cơ bản dở dang 40.17 tỷ VND với nhiều dự án cải tạo nhà xưởng đang triển khai.', 5, 'Công ty Cổ phần X20 hoạt động trong ngành may mặc, doanh thu 1,043 tỷ VND, lợi nhuận sau thuế 30.7 tỷ VND. Biên lợi nhuận gộp đạt 13.3%. Công ty có quan hệ mật thiết với Bộ Quốc phòng qua các cổ đông Nhà nước (72% sở hữu) và vay vốn từ Cục tài chính Bộ Quốc phòng. Tổng tài sản 852 tỷ VND tăng 23% so với đầu năm. Điểm rủi ro chính là nợ ngắn hạn chiếm tỷ trọng lớn, hàng tồn kho tăng mạnh, và nhiều dự án xây dựng dở dang. Công ty có công ty con và liên kết, giao dịch liên kết cần được giám sát. Triển vọng trung bình, phù hợp với nhà đầu tư tìm kiếm cổ tức ổn định (tỷ suất ~12%).'),
('X20_2017_parent', 'X20', 2017, 'parent', 'Công ty có giao dịch mua bán lớn với các công ty con (X20 Nam Định 110.6 tỷ, X20 Thái Nguyên 53.5 tỷ, X20 Thanh Hóa 28.6 tỷ) và công ty liên kết Công ty CP 199 (18.7 tỷ). Công ty cũng góp vốn thành lập 3 công ty con với tổng vốn 47.5 tỷ trong năm 2017. Số dư phải thu với công ty con X20 Nam Định là 10.7 tỷ, X20 Thanh Hóa 2.4 tỷ. Các giao dịch này có tính tập trung cao, tuy nhiên không có bằng chứng về giao dịch bất thường rõ ràng như mua bán chênh lệch giá lớn hay cho vay không lãi suất.', 'Nợ vay ngắn hạn chiếm tỷ trọng rất lớn: 240 tỷ VND (toàn bộ là nợ ngắn hạn), tăng từ 191.3 tỷ đầu năm. Nợ dài hạn rất nhỏ chỉ 800 triệu. Chi phí lãi vay năm 2017 là 640.5 triệu VND. Công ty có tỷ lệ nợ/vốn chủ sở hữu cao (nợ phải trả 553 tỷ vs vốn chủ sở hữu 260 tỷ), tạo áp lực thanh khoản ngắn hạn đáng kể. Tiền và tương đương tiền cuối kỳ đạt 68.7 tỷ, tăng mạnh từ 23.8 tỷ đầu kỳ nhờ hoạt động kinh doanh tạo dòng tiền dương 120.9 tỷ.', 'Hàng tồn kho cuối kỳ 233.5 tỷ VND (giá gốc), giảm nhẹ so với đầu năm 239.2 tỷ. Dự phòng giảm giá hàng tồn kho chỉ 22.4 triệu VND (rất nhỏ so với giá trị tồn kho). Trong đó, chi phí SXKD dở dang chiếm 119.8 tỷ (51% tổng tồn kho) và nguyên vật liệu 52.3 tỷ. Thành phẩm giảm mạnh từ 63.4 tỷ xuống 19.9 tỷ cho thấy tốc độ tiêu thụ tốt. Dự án xây dựng dở dang 40.2 tỷ (tăng từ 22.1 tỷ) tập trung cải tạo nhà xưởng tại XN May 20C và XN Dệt Nam Định.', 5, 'Công ty CP X20 hoạt động trong lĩnh vực may mặc, có quy mô tổng tài sản 813 tỷ VND. Doanh thu thuần đạt 1,016.6 tỷ (tương đương năm trước), lợi nhuận sau thuế 30.7 tỷ (giảm 6.5%). Biên lợi nhuận gộp ổn định ~12.4%. Điểm mạnh: dòng tiền từ hoạt động kinh doanh dương mạnh 120.9 tỷ, tiền mặt tăng gần 3 lần. Điểm rủi ro: nợ ngắn hạn lớn 240 tỷ, tập trung giao dịch với công ty con, chi phí SXKD dở dang chiếm tỷ trọng cao trong tồn kho. Công ty đang mở rộng quy mô qua góp vốn 47.5 tỷ thành lập 3 công ty con. Kiểm toán viên đưa ra ý kiến chấp nhận toàn phần.'),
('X20_2019_parent', 'X20', 2019, 'parent', 'Công ty có nhiều giao dịch với các công ty con, bao gồm cho thuê, mua bán hàng hóa và cho vay. Các giao dịch này có vẻ bình thường trong tập đoàn, nhưng cần lưu ý về tính minh bạch và giá cả.', 'Nợ vay ngắn hạn giảm đáng kể từ 119 tỷ xuống 46,5 tỷ, áp lực nợ vay giảm. Tài sản thế chấp không được đề cập rõ ràng, nhưng lãi suất theo thỏa thuận.', 'Hàng tồn kho giảm mạnh từ 252,8 tỷ xuống 72,3 tỷ, cho thấy hàng tồn kho được quản lý tốt và không có dấu hiệu ứ đọng.', 5, 'Công ty có tình hình tài chính ổn định với lợi nhuận sau thuế 2,65 tỷ. Tuy nhiên, doanh thu giảm so với năm trước, cần cải thiện hiệu quả kinh doanh.'),
('X20_2018_consolidated', 'X20', 2018, 'consolidated', 'Công ty có giao dịch với Công ty cổ phần 199 là công ty liên kết (sở hữu 33,4%), bao gồm mua bán vật tư, cho thuê TSCĐ, cho thuê mặt bằng. Đáng lưu ý có khoản điều chỉnh giảm giá vật tư lớn 804 triệu VND. Số dư cuối kỳ: phải thu 17 triệu VND, phải trả hơn 1,06 tỷ VND với bên liên quan này. Các giao dịch này có mức độ rủi ro trung bình, cần đánh giá tính thị trường của giá giao dịch.', 'Nợ vay ngắn hạn giảm mạnh từ 243 tỷ VND xuống còn 128 tỷ VND, cho thấy công ty đã tích cực trả nợ. Phần lớn nợ vay từ Cục tài chính Bộ Quốc phòng (72 tỷ VND) - đây là nguồn vốn ưu đãi từ cơ quan chủ quản. Nợ vay ngân hàng thương mại còn lại khoảng 56 tỷ VND với lãi suất 10%/năm hoặc theo thỏa thuận. Tiền mặt cuối kỳ chỉ còn 35 tỷ VND, trong khi nợ phải trả ngắn hạn lên đến 689 tỷ VND, tạo áp lực thanh toán đáng kể.', 'Hàng tồn kho tăng từ 269 tỷ VND lên 301 tỷ VND. Chi phí SXKD dở dang chiếm tỷ trọng lớn (136 tỷ VND), cần theo dõi tiến độ hoàn thành. Dự phòng giảm giá hàng tồn kho chỉ có 53 triệu VND trên tổng giá trị 301 tỷ VND là rất thấp, cho thấy công ty đánh giá hàng tồn kho ít rủi ro. Dự án xây dựng cơ bản dở dang trị giá 31,8 tỷ VND, trong đó nhà xưởng XN dệt Nam Định chiếm 30,6 tỷ VND.', 6, 'Công ty X20 hoạt động trong lĩnh vực sản xuất công nghiệp, có quan hệ mật thiết với Bộ Quốc phòng (71,72% vốn nhà nước). Doanh thu ổn định quanh 1.048 tỷ VND, lợi nhuận gộp biên khoảng 13%. Công ty đã giảm đáng kể nợ vay ngắn hạn trong năm 2018. Tuy nhiên, áp lực thanh toán nợ ngắn hạn vẫn cao khi tiền mặt chỉ còn 35 tỷ VND so với nợ ngắn hạn 689 tỷ VND. Ban lãnh đạo kiêm nhiệm nhiều vị trí (Tổng Giám đốc đồng thời là Phó Chủ tịch HĐQT). Công ty có đầu tư vào Công ty cổ phần 199 (liên kết) và công ty con tại nhiều địa phương. Triển vọng kinh doanh phụ thuộc lớn vào hợp đồng với Cục Quân nhu và tiến độ các dự án xây dựng.'),
('X20_2018_parent', 'X20', 2018, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm công ty con và công ty liên kết. Các giao dịch bao gồm mua bán hàng hóa, cho thuê tài sản, gia công và cho vay. Đặc biệt, công ty cho vay Công ty TNHH MTV X20 Nam Định số tiền 21,600,000,000 VND, có thể tiềm ẩn rủi ro thu hồi nợ và thiếu minh bạch về giá chuyển nhượng.', 'Nợ ngắn hạn còn lại 119,033,435,029 VND, giảm mạnh so với đầu năm nhưng vẫn ở mức cao. Chi phí lãi vay tương đối thấp, nhưng công ty phụ thuộc vào vay ngắn hạn, có rủi ro tái tài chính. Dòng tiền từ hoạt động kinh doanh đủ để trả lãi nhưng áp lực thanh toán nợ gốc vẫn tồn tại.', 'Hàng tồn kho lớn, chủ yếu là nguyên liệu và thành phẩm, với dự phòng giảm giá nhỏ. Có nhiều dự án xây dựng dở dang, cần giám sát tiến độ và hiệu quả đầu tư để tránh ứ đọng vốn.', 5, 'Công ty ghi nhận doanh thu giảm nhưng vẫn có lợi nhuận. Nợ ngắn hạn đã giảm đáng kể, cải thiện cơ cấu tài sản. Tuy nhiên, giao dịch bên liên quan phức tạp và tỷ lệ tồn kho cao tiềm ẩn rủi ro. Tình hình tài chính ổn định nhưng tăng trưởng chậm lại.'),
('WTC_2025_consolidated', 'WTC', 2025, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu với công ty mẹ Công ty TNHH Vận tải Việt Thuận và các công ty liên quan. Các giao dịch bao gồm cho thuê, vận chuyển, mua bán hàng hóa và dịch vụ, nhận vốn góp và trả cổ tức. Giá trị giao dịch lớn nhưng phù hợp với hoạt động kinh doanh chính, không có dấu hiệu bất thường như mua bán chênh lệch lớn hay cho vay không lãi suất.', 'Nợ vay tăng mạnh từ 258,9 tỷ VNĐ lên 772,0 tỷ VNĐ,主要用于 đầu tư mua tàu vận tải biển và đóng mới tàu. Công ty có nhiều khoản vay dài hạn với lãi suất cố định hoặc thả nổi, được đảm bảo bằng tài sản hình thành từ vốn vay và tiền gửi. Áp lực nợ vay tăng cao nhưng được hỗ trợ bởi dòng tiền hoạt động kinh doanh dương và kế hoạch mở rộng kinh doanh.', 'Hàng tồn kho tăng nhẹ từ 9,3 tỷ VNĐ lên 10,9 tỷ VNĐ, chủ yếu là nguyên liệu và chi phí sản xuất dở dang liên quan đến dự án đóng tàu. Không trích lập dự phòng giảm giá hàng tồn kho, cho thấy hàng tồn kho không bị滞销 hoặc giảm giá. Dự án xây dựng cơ bản dở dang tăng mạnh do đầu tư mua vỏ tàu, có thể ảnh hưởng đến dòng tiền nhưng là đầu tư chiến lược.', 4, 'Công ty có kết quả kinh doanh ổn định với lợi nhuận sau thuế đạt 11,3 tỷ VNĐ. Công ty đang trong giai đoạn mở rộng mạnh mẽ, đầu tư vào tàu vận tải biển thông qua tăng vốn chủ sở hữu và vay nợ lớn. Dù nợ vay tăng cao,但 công ty có tài sản đảm bảo và dòng tiền hoạt động kinh doanh cải thiện. Rủi ro quản trị ở mức trung bình do giao dịch với các bên liên quan có liên quan gia đình ban lãnh đạo. Triển vọng đầu tư tích cực trong dài hạn nếu công ty quản lý tốt nợ vay và tận dụng được lợi thế từ đội tàu mở rộng.'),
('WTC_2023_consolidated', 'WTC', 2023, 'consolidated', 'Công ty có giao dịch với nhiều bên liên quan, bao gồm công ty mẹ và cá nhân liên quan. Giao dịch chủ yếu là mua bán hàng hóa, dịch vụ và cho vay với lãi suất từ 9% đến 12%/năm, không có tài sản thế chấp. Không có bằng chứng về giao dịch bất thường hay giá trị chênh lệch lớn.', 'Công ty không có nợ vay tại thời điểm cuối năm 2023, do đó áp lực nợ thấp.', 'Hàng tồn kho bao gồm nguyên liệu, công cụ và chi phí dở dang, với dự phòng giảm giá bằng 0. Chi phí sản xuất dở dang giảm so với năm trước, cho thấy kiểm soát tốt.', 4, 'Công ty có doanh thu giảm mạnh do không kí được hợp đồng mua bán than pha trộn, nhưng lợi nhuận vẫn dương. Nợ vay không có, tài sản cố định tăng do mua sắm. Tình hình tài chính ổn định, nhưng phụ thuộc vào hoạt động vận tải và kinh doanh than thương mại.'),
('WTC_2022_consolidated', 'WTC', 2022, 'consolidated', 'Công ty có mạng lưới giao dịch bên liên quan phức tạp, bao gồm cho vay lớn với lãi suất 11.5%/năm cho công ty mẹ (Việt Thuận) và giao dịch thương mại với nhiều công ty liên quan. Các giao dịch này có thể có xung đột lợi ích nhưng được thực hiện theo điều kiện thị trường.', 'Tính đến cuối năm 2022, công ty không có khoản vay ngắn hạn hoặc dài hạn, rủi ro nợ vay rất thấp.', 'Hàng tồn kho bao gồm nguyên liệu, công cụ và chi phí sản xuất dở dang, tổng giá trị khoảng 120 tỷ VNĐ, không có dự phòng giảm giá. Tốc độ lưu chuyển có thể bị ảnh hưởng bởi tính mùa vụ của kinh doanh than.', 6, 'Năm 2022 doanh thu giảm nhưng lợi nhuận ròng tăng. Công ty không có gánh nặng nợ, dòng tiền cải thiện. Cần theo dõi rủi ro giao dịch bên liên quan, nhưng tình hình tài chính tổng thể ổn định.'),
('WTC_2020_consolidated', 'WTC', 2020, 'consolidated', 'Doanh nghiệp có quan hệ kinh doanh mật thiết và giao dịch lớn với các bên liên quan, bao gồm công ty mẹ (Công ty TNHH Vận tải Việt Thuận) và các công ty cùng lãnh đạo (Trường Nguyên). Giao dịch mua bán hàng hóa/dịch vụ với tổng giá trị hàng trăm tỷ đồng diễn ra thường xuyên, có thể đặt ra câu hỏi về tính độc lập và công bằng về giá. Tuy nhiên, chưa có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất hay chênh lệch giá lớn.', 'Công ty có cấu trúc nợ ngắn hạn rất lớn với tổng dư nợ cuối kỳ đạt hơn 666 tỷ VND, chủ yếu từ vay ngân hàng. Áp lực trả nợ là đáng kể, đặc biệt trong bối cảnh dòng tiền từ hoạt động kinh doanh âm. Đa phần các khoản vay đều được đảm bảo bằng tài sản (tàu, bất động sản) hoặc bảo lãnh, giảm thiểu rủi ro cho người cho vay nhưng tạo áp lực tài sản lên doanh nghiệp.', 'Hàng tồn kho cuối kỳ ở mức cao (khoảng 447 tỷ VND), trong đó hàng hóa (thành phẩm than) chiếm phần lớn. Không có dự phòng giảm giá hàng tồn kho được trích lập, cho thấy ban lãnh đạo đánh giá khả năng tiêu thụ và giá trị thuần có thể thực hiện được là khả quan. Tuy nhiên, ngành than có tính chu kỳ và biến động giá, đây là yếu tố rủi ro tiềm ẩn.', 7, 'Công ty vận tải thủy - Vinacomin hoạt động trong ngành vận tải và chế biến than, có doanh thu tăng trưởng mạnh trong năm 2020. Tuy nhiên, lợi nhuận sau thuế giảm nhẹ. Sức khỏe tài chính có điểm đáng lo ngại: tỷ lệ nợ vay ngắn hạn rất cao, dòng tiền hoạt động kinh doanh âm nặng nề (-277 tỷ VND) do tăng mạnh các khoản phải thu và tồn kho. Công ty phụ thuộc lớn vào nguồn vốn vay ngắn hạn ngân hàng. Mối quan hệ mật thiết với các bên liên quan là một đặc điểm quản trị cần theo dõi. Triển vọng phụ thuộc vào khả năng quản lý dòng tiền, kiểm soát tồn kho và duy trì quan hệ tín dụng.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('WTC_2021_consolidated', 'WTC', 2021, 'consolidated', 'Doanh nghiệp có mức độ giao dịch với bên liên quan rất lớn. Doanh thu bán cho Công ty TNHH Vận tải Kinh doanh XNK Trường Nguyên (cùng chủ tịch HĐQT) chiếm tỷ trọng rất cao (1.747 tỷ VNĐ, ~36% tổng doanh thu). Tổng cho vay bên liên quan lên tới 218 tỷ VNĐ (Công ty TNHH Vận tải Việt Thuận - công ty mẹ: 178 tỷ VNĐ dài hạn tín chấp lãi suất 9%; Công ty TNHH Việt Thuận Hotel - cùng chủ tịch HĐQT: 40 tỷ VNĐ ngắn hạn tín chấp lãi suất 9%). Trả trước cho Chủ tịch HĐQT Trịnh Trung Úy 6,2 tỷ VNĐ. Các khoản vay tín chấp lớn cho bên liên quan có mức độ rủi ro cao. Tuy nhiên, Công ty TNHH Vận tải Việt Thuận đã thế chấp tàu Việt Thuận 09 (22 tỷ) đảm bảo cho khoản vay ngân hàng của Công ty.', 'Áp lực nợ vay đã giảm đáng kể trong năm 2021: nợ ngắn hạn giảm từ 666,6 tỷ VNĐ xuống chỉ còn 16,95 tỷ VNĐ (giảm 97,5%). Chỉ còn duy nhất khoản vay tại BIDV CN Hạ Long 16,95 tỷ VNĐ. Công ty đã thanh lý tài sản lớn (tàu Vinacomin Ocean) để trả nợ, làm giảm mạnh tổng tài sản. Chi phí lãi vay giảm từ 39,7 tỷ xuống 16 tỷ VNĐ. Tuy nhiên, tỷ lệ nợ vay trên vốn chủ sở hữu đã giảm về mức thấp.', 'Hàng tồn kho giảm mạnh từ 447 tỷ VNĐ xuống chỉ còn 13 tỷ VNĐ (giảm 97%), do Công ty tạm dừng hoạt động kinh doanh chế biến than hơn nửa năm do không ký được hợp đồng mua bán than với TKV. Hàng hóa (thành phẩm chế biến) giảm từ 437 tỷ xuống 0 đồng. Tồn kho chủ yếu là nguyên liệu vật liệu (11,8 tỷ) và chi phí SXKD dở dang (1,2 tỷ). Không có dự phòng giảm giá hàng tồn kho. Rủi ro thấp do Công ty đã thoái hầu hết hàng tồn kho.', 5, 'Năm 2021, Công ty CP Vận tải thủy - Vinacomin gặp nhiều khó khăn: doanh thu giảm 30,7% (từ 6.981 tỷ xuống 4.835 tỷ VNĐ) do tạm dừng kinh doanh chế biến than hơn nửa năm; hoạt động kinh doanh chính bị lỗ thuần 31,26 tỷ VNĐ. Tuy nhiên, Công ty đã thực hiện thoái vốn lớn (bán tàu Vinacomin Ocean) thu về 76,68 tỷ VNĐ lợi nhuận khác, giúp lợi nhuận trước thuế đạt 45,49 tỷ và LNST đạt 36,36 tỷ VNĐ. Tổng tài sản giảm mạnh từ 961 tỷ xuống 296 tỷ VNĐ (-69%). Điểm tích cực: nợ vay ngân hàng giảm mạnh 97,5%, dòng tiền hoạt động kinh doanh dương 727 tỷ VNĐ nhờ thu hồi các khoản phải thu và giảm tồn kho. Công ty tiếp tục chi trả cổ tức 35 tỷ VNĐ. Rủi ro chính là giao dịch lớn với bên liên quan (cho vay tínấp 218 tỷ VNĐ), phụ thuộc lớn vào hợp đồng mua bán than với TKV/Việt Thuận, và chưa có kế hoạch kinh doanh than chế biến cho năm 2022.'),
('WTC_2018_consolidated', 'WTC', 2018, 'consolidated', 'Doanh nghiệp có giao dịch lớn với các bên liên quan, đặc biệt là các công ty trong cùng tập đoàn Công nghiệp Than - Khoáng sản Việt Nam. Doanh thu chủ yếu đến từ dịch vụ vận chuyển cho các công ty liên quan, có nguy cơ lợi ích nhóm hoặc giá cả không thị trường.', 'Nợ ngắn hạn vượt quá tài sản ngắn hạn, gây nghi ngờ về khả năng hoạt động liên tục. Tuy nhiên, công ty có kế hoạch cải thiện và dòng tiền kinh doanh dương.', 'Hàng tồn kho không có dự phòng giảm giá, nhưng tồn kho bao gồm nguyên liệu và chi phí sản xuất dở dang, cần theo dõi khả năng tiêu thụ.', 7, 'Công ty có sự cải thiện về lợi nhuận so với năm trước, nhưng áp lực nợ vay lớn và phụ thuộc vào giao dịch với bên liên quan. Cần giám sát chặt chẽ về quản trị rủi ro và đa dạng hóa khách hàng.'),
('WTC_2019_consolidated', 'WTC', 2019, 'consolidated', 'Công ty có giao dịch vay mượn và mua bán với các bên liên quan, bao gồm công ty mẹ và cá nhân quản lý chủ chốt. Các giao dịch này theo giá thỏa thuận và không có bảo đảm rõ ràng, nhưng không phát hiện giao dịch bất thường.', 'Áp lực nợ vay ngắn hạn cao với tổng dư nợ cuối năm hơn 391 tỷ VNĐ, chi phí lãi vay năm nay hơn 16 tỷ VNĐ. Công ty có tài sản thế chấp là TSCĐ, nhưng cần theo dõi khả năng thanh toán.', 'Tồn kho tăng mạnh từ 9.3 tỷ lên 417.5 tỷ VNĐ, chủ yếu do hàng hóa trên đường và hàng hóa thành phẩm. Không có dự phòng giảm giá, nhưng cần đánh giá khả năng tiêu thụ.', 6, 'Công ty tăng trưởng mạnh về doanh thu và lợi nhuận, nhưng nợ vay và tồn kho tăng nhanh gây áp lực lên vốn lưu động. Cần theo dõi quản lý nợ và tiêu thụ hàng hóa.'),
('WSS_2024_consolidated', 'WSS', 2024, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là thu nhập từ Công ty Cổ phần Đầu tư Tài chính Giáo dục và lương thưởng cho ban lãnh đạo, không có giao dịch bất thường đáng kể như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty không có nợ vay, chỉ có các khoản phải trả ngắn hạn như phải trả người bán và chi phí phải trả, áp lực nợ thấp và khả năng thanh toán tốt.', 'Dự án xây dựng phần mềm dở dang với giá trị nhỏ (600 triệu VNĐ), không có hàng tồn kho truyền thống, rủi ro tồn kho thấp.', 2, 'Công ty chịu lỗ nặng trong năm 2024 do ảnh hưởng tiêu cực của thị trường chứng khoán, dẫn đến giảm giá trị đầu tư. Tuy nhiên, công ty có vốn chủ sở hữu mạnh (hơn 483 tỷ VNĐ) và không có nợ vay, đảm bảo an toàn tài chính. Triển vọng phụ thuộc vào sự phục hồi của thị trường chứng khoán và hiệu quả hoạt động kinh doanh.'),
('WTC_2015_consolidated', 'WTC', 2015, 'consolidated', 'Công ty có giao dịch lớn với Tập đoàn Công nghiệp Than - Khoáng sản Việt Nam và các đơn vị thành viên, bao gồm doanh thu, mua hàng, bán tài sản và thuê tàu. Việc bán tàu sau đó thuê lại có thể cho thấy rủi ro liên quan đến giao dịch không minh bạch, nhưng giá cả được xác định theo thẩm định giá. Tuy nhiên, không có bằng chứng về giao dịch bất thường như cho vay không lãi suất hoặc mua bán chênh lệch lớn.', 'Công ty có nợ vay ngắn hạn và dài hạn, trong đó nợ ngắn hạn vượt quá tài sản ngắn hạn. Có khoản vay không lãi suất từ tập đoàn mẹ, nhưng áp lực nợ vay cao do lỗ lũy kế. Tài sản thế chấp là tàu và khoản phải thu.', 'Hàng tồn kho chủ yếu là nguyên liệu và công cụ dụng cụ, không có dự án xây dựng dở dang. Không có dự phòng giảm giá tồn kho, cho thấy rủi ro thấp.', 6, 'Công ty đang gặp khó khăn tài chính với lỗ lũy kế lớn và nợ ngắn hạn cao. Tuy nhiên, có sự hỗ trợ từ tập đoàn mẹ. Triển vọng đầu tư thận trọng.'),
('WSS_2025_consolidated', 'WSS', 2025, 'consolidated', 'Công ty có giao dịch mua bán cổ phần trị giá lớn với các bên liên quan: chuyển nhượng cổ phần 6,2 tỷ VNĐ cho Công ty Cổ phần Đầu tư Tài chính Giáo dục và nhận chuyển nhượng cổ phần 49 tỷ VNĐ từ Công ty Cổ phần Đầu tư Tài chính Công nghệ BVA (cùng liên quan đến Phó Chủ tịch HĐQT Phạm Đức Long). Khoản phải thu 49 tỷ VNĐ từ Công ty Cổ phần Đầu tư và Phát triển Hạ tầng Hoàng Thành phát sinh từ giao dịch mua cổ phần qua bên liên quan BVA. Tổng giá trị giao dịch bên liên quan trong năm đạt hơn 104 tỷ VNĐ, mức đáng kể so với vốn chủ sở hữu 529 tỷ VNĐ. Tuy nhiên, giao dịch được thực hiện theo nghị quyết HĐQT và đã hoàn tất thủ tục chuyển nhượng.', 'Công ty không có nợ vay ngân hàng hay trái phiếu, toàn bộ nợ phải trả là nợ ngắn hạn hoạt động với tổng trị giá 6,2 tỷ VNĐ - mức rất nhỏ so với tài sản ngắn hạn 520,7 tỷ VNĐ và tiền gửi có kỳ hạn 351 tỷ VNĐ. Công ty có khả năng thanh toán nợ rất tốt, không có áp lực nợ vay. Tuy nhiên, Công ty có kế hoạch phát hành riêng lẻ 10 triệu cổ phiếu để tăng vốn điều lệ lên 603 tỷ VNĐ.', 'Rủi ro tồn kho thấp. Công ty không có hàng hóa tồn kho (công ty chứng khoán). Chi phí xây dựng dở dang chỉ 350 triệu VNĐ cho dự án phần mềm giao dịch mobile, quy mô nhỏ. Rủi ro chính nằm ở danh mục đầu tư chứng khoán FVTPL trị giá 98,2 tỷ VNĐ (giảm từ 117,9 tỷ giá gốc do đánh giá giảm giá trị), với khoản lỗ đánh giá giảm chưa thực hiện 19,7 tỷ VNĐ. Danh mục đầu tư vào cổ phiếu chưa niêm yết có mức giảm giá trị lớn.', 4, 'Công ty Cổ phần Chứng khoán Phố Wall có sự phục hồi mạnh về kết quả kinh doanh năm 2025 với lợi nhuận trước thuế 45,6 tỷ VNĐ (so với lỗ 31,4 tỷ năm 2024), chủ yếu nhờ hoạt động tự doanh và tư vấn tài chính. Tình hình tài chính lành mạnh: không nợ vay, tiền và đầu tư ngắn hạn dồi dào (454,7 tỷ VNĐ), vốn chủ sở hữu 529 tỷ VNĐ. Điểm mạnh: tỷ lệ nợ thấp, thanh khoản tốt. Điểm cần lưu ý: giao dịch với bên liên quan có giá trị lớn (104+ tỷ VNĐ), ban lãnh đạo giữ vị trí tại nhiều công ty liên kết, kế hoạch phát hành riêng lẻ cổ phiếu. Công ty có khoản đầu tư dài hạn vào cổ phiếu chưa niêm yết (MGG, HAF) với ban lãnh đạo có liên quan, đã thoái vốn khỏi một số khoản đầu tư OTC trong năm.'),
('WSS_2023_consolidated', 'WSS', 2023, 'consolidated', 'Công ty có mối quan hệ phức tạp với nhiều bên liên quan qua các thành viên HĐQT và Ban Kiểm soát. Các khoản đầu tư lớn vào Công ty Cổ phần Thực phẩm Hà Nội (HAF, giá trị hợp lý 72.55 tỷ VND), Tổng Công ty Đức Giang - CTCP (MGG, 63 tỷ VND) và Công ty Cổ phần Halas Việt Nam (13.5 tỷ VND) đều liên quan đến Chủ tịch HĐQT và Trưởng ban Kiểm soát. Ngoài ra, Công ty ứng trước 95 tỷ VND cho Công ty Cổ phần An Sinh thuê văn phòng nhưng đối tác chậm bàn giao, đã phải thanh lý hợp đồng và thu hồi dần tiền. Các khoản thù lao cho HĐQT và Ban Kiểm soát năm 2023 là 869.760.517 VND. Công ty bị Ủy ban Chứng khoán Nhà nước xử phạt vi phạm hành chính 777.5 triệu VND (Quyết định 623/QĐ-XPHC ngày 24/07/2023) do không quản lý tách biệt tài sản khách hàng, ứng trước tiền bán chứng khoán khi chưa được chấp thuận và công bố thông tin không đầy đủ về bên liên quan.', 'Công ty không có nợ vay ngân hàng hay tổ chức tín dụng. Tổng nợ phải trả ngắn hạn chỉ 3.72 tỷ VND, chiếm 0.72% tổng tài sản 518.6 tỷ VND. Nợ phải trả chủ yếu là người mua trả trước (885.5 triệu VND), phải trả người lao động (1.02 tỷ VND) và phải trả cổ tức cho cổ đông (1.1 tỷ VND). Áp lực nợ vay rất thấp, Công ty hoạt động chủ yếu bằng vốn chủ sở hữu (514.88 tỷ VND). Tuy nhiên, Công ty có khoản tiền nộp Quỹ Hỗ trợ thanh toán 4.81 tỷ VND là bắt buộc theo quy định.', 'Công ty là công ty chứng khoán không có hàng tồn kho truyền thống. Rủi ro chính nằm ở danh mục đầu tư tài chính: FVTPL có giá trị hợp lý 168.16 tỷ VND nhưng giá gốc 194.79 tỷ VND (lỗ chưa thực hiện ~26.6 tỷ VND); AFS giá trị hợp lý 66.42 tỷ VND nhưng giá gốc 73.75 tỷ VND (lỗ chưa thực hiện ~7.3 tỷ VND). Dự phòng suy giảm AFS là 7.33 tỷ VND. Đầu tư dài hạn khác trị giá 19.75 tỷ VND đã trích dự phòng 968.5 triệu VND. Tổng lỗ chưa thực hiện là 26.63 tỷ VND, cho thấy rủi ro suy giảm giá trị danh mục đầu tư đáng kể.', 7, 'Công ty Cổ phần Chứng khoán Phố Wall là công ty chứng khoán nhỏ với vốn điều lệ 503 tỷ VND, 31 nhân viên, niêm yết trên HNX với mã WSS. Năm 2023, Công ty có lãi kế toán 1.65 tỷ VND (sau lỗ 18.61 tỷ VND năm 2022), nhưng lợi nhuận đã thực hiện là lỗ 5.7 tỷ VND, phần lãi chủ yếu đến từ đánh giá lại tài sản tài chính chưa thực hiện (+7.35 tỷ VND). Doanh thu hoạt động 42.51 tỷ VND, chi phí hoạt động 34.33 tỷ VND. Tỷ suất lợi nhuận hoạt động ~5.3%. Công ty có cấu trúc vốn an toàn với tỷ lệ nợ/tài sản rất thấp (0.72%), tiền mặt 22.27 tỷ VND tăng mạnh so với đầu năm. Tuy nhiên, Công ty có nhiều rủi ro về quản trị: giao dịch phức tạp với bên liên quan qua các thành viên HĐQT, vi phạm quy định pháp luật và bị xử phạt hành chính, khoản ứng trước 95 tỷ VND gặp rủi ro thu hồi. Lợi nhuận đã thực hiện lỗ liên tục (lỗ 12.23 tỷ VND năm 2022, lỗ 5.7 tỷ VND năm 2023), cho thấy hiệu quả kinh doanh cốt lõi yếu.'),
('WSS_2022_consolidated', 'WSS', 2022, 'consolidated', '关联交易主要为董事和监事的薪酬支付，未发现异常交易，风险较低。', '公司负债以短期应付款为主，无长期借款，负债水平低，偿付压力小。', '公司为证券公司，无存货，因此无存货风险。', 2, '公司2022年出现亏损，主要原因是金融资产投资损失。但负债水平低，资产流动性较好。需关注投资风险。'),
('WSS_2018_consolidated', 'WSS', 2018, 'consolidated', 'Công ty chỉ giao dịch thu nhập với Ban lãnh đạo, không có giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty có nợ vay ngắn hạn 55 tỷ VND với tài sản thế chấp là tiền gửi, nhưng tiền mặt giảm mạnh từ 159 tỷ xuống 68 tỷ, cần theo dõi khả năng thanh toán.', 'Không có hàng tồn kho do công ty hoạt động trong lĩnh vực chứng khoán, không có rủi ro tồn kho dở dang.', 3, 'Công ty có kết quả kinh doanh tốt năm 2018 với lợi nhuận sau thuế 45 tỷ VND, tăng mạnh so với năm trước, chủ yếu từ đánh giá lại tài sản tài chính. Tuy nhiên, tiền mặt giảm và nợ vay tăng, cần cải thiện quản lý thanh khoản. Tình hình tài chung ổn định, nhưng rủi ro thị trường chứng khoán vẫn tồn tại.'),
('WSS_2020_consolidated', 'WSS', 2020, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm đầu tư vào 2 công ty liên kết với tỷ lệ sở hữu 14% và 10,99%. Đặc biệt, có 2 khoản ứng trước lớn với tổng giá trị 85,4 tỷ đồng cho Bà Nguyễn Thanh Bích Hà (mua nhà) và Công ty Cổ phần An Sinh (thuê văn phòng), tuy nhiên cả hai khoản này đã được hủy kế hoạch và hoàn trả trong Quý I/2021 theo quyết định của HĐQT. Không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Các khoản thù lao cho HĐQT và ban giám đốc được công khai minh bạch.', 'Áp lực nợ vay đã giảm đáng kể trong năm 2020. Công ty đã trả hết khoản vay ngắn hạn 44 tỷ đồng tại Ngân hàng TMCP Bắc Á, từ đó đến cuối năm không còn nợ vay ngân hàng. Nợ phải trả ngắn hạn chỉ còn 3,78 tỷ đồng, giảm mạnh so với 48,56 tỷ đồng đầu năm. Không có nợ dài hạn. Tỷ lệ nợ/vốn chủ sở hữu rất thấp (0,72%), cho thấy công ty có cấu trúc vốn an toàn và khả năng thanh toán tốt.', 'Công ty là công ty chứng khoán nên không có hàng tồn kho truyền thống hay dự án xây dựng dở dang. Rủi ro chính liên quan đến các khoản ứng trước bất động sản (85,4 tỷ đồng) nhưng đã được hoàn trả thành công trong Quý I/2021. Các khoản đầu tư tài chính có rủi ro biến động giá trị thị trường nhưng đã được đánh giá lại thường xuyên theo quy định.', 3, 'Công ty CP Chứng khoán Phố Wall đã có sự phục hồi mạnh trong năm 2020 với lợi nhuận sau thuế 10,7 tỷ đồng sau khoản lỗ nặng 79,9 tỷ đồng năm 2019. Nợ vay đã được trả hết, cấu trúc vốn an toàn. Công ty đã cơ cấu lại danh mục đầu tư, thanh lý khoản đầu tư AFS lãi 18 tỷ đồng và hủy kế hoạch mua/thuê bất động sản để tối ưu hóa sử dụng vốn. Tuy nhiên, công ty còn khoản lỗ chưa thực hiện 14,1 tỷ đồng từ đánh giá lại tài sản FVTPL và một số khoản đầu tư vào cổ phiếu chưa niêm yết có giá trị thị trường thấp hơn giá gốc đáng kể (như HAF, ILS). Công ty đã tuân thủ các quy định về quản trị công ty và không vi phạm nghĩa vụ công bố thông tin.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('X26_2025_consolidated', 'X26', 2025, 'consolidated', 'Công ty có mối quan hệ chặt chẽ với các đơn vị thuộc Bộ Quốc phòng, đặc biệt doanh thu bán hàng cho Cục Quân nhu chiếm tỷ trọng lớn (>50% doanh thu). Giao dịch mua bán diễn ra thường xuyên, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch giá lớn. Tuy nhiên, sự phụ thuộc vào một nhóm khách hàng liên quan tạo ra rủi ro tập trung doanh thu.', 'Nợ vay toàn bộ là ngắn hạn với lãi suất biến động (2,2%-5,5%/năm), được đảm bảo bằng tiền gửi có kỳ hạn. Tỷ lệ nợ vay trên vốn chủ sở hữu thấp (6,4%), áp lực trả nợ không đáng kể. Công ty có dòng tiền hoạt động kinh doanh dương và tỷ lệ thanh toán nhanh đảm bảo khả năng trả nợ.', 'Hàng tồn kho giảm 14,6% so với đầu năm, không có dự phòng giảm giá. Chi phí sản xuất dở dang còn tồn đọng nhưng không có dấu hiệu ứ đọng nghiêm trọng. Rủi ro tồn kho ở mức kiểm soát được.', 5, 'Công ty duy trì hoạt động sản xuất kinh doanh ổn định với biên lợi nhuận gộp 10,5%. Doanh thu giảm nhẹ nhưng lợi nhuận sau thuế vẫn dương. Cơ cấu tài chính an toàn với nợ vay thấp và tài sản đảm bảo đầy đủ. Điểm rủi ro chính là phụ thuộc vào khách hàng liên quan đến Bộ Quốc phòng. Công ty có triển vọng phát triển ổn định trong ngành sản xuất công nghiệp.'),
('X20_2022_parent', 'X20', 2022, 'parent', 'Công ty có giao dịch lớn với các công ty con, đặc biệt cho vay với lãi suất thấp (0.5%/năm) và mua bán hàng hóa, điều này có thể ảnh hưởng đến lợi nhuận và tạo rủi ro quản trị.', 'Công ty không có nợ vay ngân hàng, nợ chủ yếu là phải trả ngắn hạn từ hoạt động kinh doanh, áp lực thanh toán thấp và không có tài sản thế chấp.', 'Hàng tồn kho giảm so với đầu năm và có dự phòng giảm giá, nhưng giá trị vẫn lớn, rủi ro tồn kho ở mức trung bình.', 5, 'Công ty tăng trưởng mạnh về doanh thu và lợi nhuận trong năm 2022, dòng tiền kinh doanh dương, nhưng phụ thuộc nhiều vào giao dịch với bên liên quan. Tình hình tài cơ bản ổn định, không có nợ vay lớn.'),
('WSS_2017_consolidated', 'WSS', 2017, 'consolidated', 'Công ty có giao dịch đáng kể với bên liên quan Công ty Cổ phần Đầu tư và Phát triển Đô thị Phố Wall (tỷ lệ sở hữu 14%): chuyển nhượng khoản đầu tư 23.04 tỷ VNĐ, ứng trước 44 tỷ VNĐ cho dự án bất động sản và đầu tư dài hạn 14 tỷ VNĐ. Dự án Trung tâm Thương mại 52 Ngọc Lâm có thời hạn bàn giao 36 tháng từ 28/12/2015, đến cuối 2017 khoản ứng trước vẫn chưa được quyết toán, cần theo dõi tiến độ dự án. Ngoài ra, thu nhập cho Tổng Giám đốc và HĐQT/BKS gần 920 triệu VNĐ trong năm.', 'Công ty có khoản vay ngắn hạn duy nhất 43 tỷ VNĐ từ Ngân hàng TMCP Bắc Á (lãi suất 7.5%/năm, đáo hạn 22/12/2018). Tỷ lệ nợ vay/vốn chủ sở hữu rất thấp (~7.9%). Tài sản thế chấp là 8 hợp đồng tiền gửi có kỳ hạn trị giá 55.64 tỷ VNĐ, tỷ lệ đảm bảo/vay đạt 129%, cho thấy khả năng trả nợ được đảm bảo tốt. Áp lực nợ vay ở mức kiểm soát được.', 'Là công ty chứng khoán nên không có hàng tồn kho truyền thống. Tuy nhiên, danh mục AFS đầu tư cổ phiếu chưa niêm yết trị giá 100.25 tỷ VNĐ (gồm các Công ty CP Đầu tư Thương mại DV Quốc tế 65 tỷ, Khu Nghi Dương & Sản Gold 32.25 tỷ, Mây Đức Giang 25.57 tỷ...) được đánh giá theo giá gốc do chưa có hướng dẫn xác định giá trị hợp lý, tiềm ẩn rủi ro đánh giá quá giá. Dự án bất động sản ứng trước 44 tỷ VNĐ cần theo dõi sát tiến độ bàn giao.', 5, 'Công ty CP Chứng khoán Phố Wall đạt lợi nhuận sau thuế 15.13 tỷ VNĐ năm 2017 (tăng 3 lần so với 4.95 tỷ VNĐ năm 2016), phần lớn nhờ lãi chưa thực hiện từ đánh giá lại FVTPL tăng 29.95 tỷ VNĐ. Tuy nhiên, lợi nhuận đã thực hiện lỗ 929 triệu VNĐ cho thấy hoạt động kinh doanh cốt lõi gặp thách thức. Cơ cấu tài chính lành mạnh với tỷ lệ nợ vay/vốn chủ sở hữu chỉ 7.9%, tiền và tương đương tiền đạt 159.31 tỷ VNĐ. Điểm đáng lưu ý: (i) giao dịch lớn với bên liên quan Phố Wall Invest gồm ứng trước 44 tỷ và đầu tư 14 tỷ vào dự án bất động sản; (ii) thay đổi nhân sự cấp cao trong năm (Tổng Giám đốc bị cách nhiệm, Phó Chủ tịch HĐQT bị miễn nhiệm); (iii) danh mục FVTPL tăng mạnh từ 11.58 tỷ lên 162.30 tỷ VNĐ phản ánh chiến lược đầu tư tích cực nhưng tiềm ẩn rủi ro biến động lớn. Điểm rủi ro quản trị ở mức trung bình.'),
('WSS_2016_consolidated', 'WSS', 2016, 'consolidated', 'Công ty có khoản ứng trước dài hạn 44 tỷ VND cho Công ty Cổ phần Đầu tư và Phát triển Đô thị Phố Wall (bên liên kết 14% vốn) để đầu tư Trung tâm Thương mại, Văn phòng và Căn hộ tại 52 Ngọc Lâm, Quận Long Biên, Hà Nội với thời hạn giao nhà 36 tháng. Đây là khoản phải thu lớn (chiếm 8.2% tổng tài sản), có tính thanh khoản thấp và phụ thuộc vào tiến độ dự án bất động sản của bên liên kết. Công ty cũng đầu tư 14 tỷ VND (2.6% tổng tài sản) vào cùng công ty này. Tổng giao dịch với bên liên kết chiếm khoảng 10.8% tổng tài sản. Không phát hiện giao dịch bất thường (cho vay không lãi suất, mua bán chênh lệch lớn).', 'Công ty không có nợ vay ngân hàng dài hạn hay ngắn hạn. Nợ phải trả chỉ gồm các khoản phải trả ngắn hạn thông thường tổng cộng 4.01 tỷ VND, chiếm tỷ lệ rất thấp 0.75% trên tổng tài sản 535.98 tỷ VND. Công ty có tiền gửi có kỳ hạn 274 tỷ VND tại Ngân hàng TMCP Bắc Á và tiền gửi tương đương tiền 64.4 tỷ VND, đảm bảo khả năng thanh khoản tốt. Các khoản cho vay margin và ứng trước tiền bán cho nhà đầu tư giảm mạnh từ 42.98 tỷ xuống 14.18 tỷ, cho thấy công ty đã thu hẹp hoạt động tín dụng. Áp lực nợ vay gần như không tồn tại.', 'Công ty là công ty chứng khoán, không có hàng tồn kho vật lý hay dự án xây dựng dở dang. Các tài sản tài chính đầu tư bao gồm: FVTPL (cổ phiếu niêm yết, Upcom) trị giá sổ sách 11.58 tỷ VND, dự phòng suy giảm giá trị giảm mạnh từ 7.02 tỷ xuống chỉ còn 5.6 triệu VND; AFS (cổ phiếu chưa niêm yết) trị giá 77.78 tỷ VND không trích lập dự phòng do không có giá thị trường. Tiền gửi có kỳ hạn HTM 274 tỷ VND tại ngân hàng với lãi suất 6.4%/năm là khoản đầu tư an toàn, sinh lời ổn định.', 4, 'Công ty Cổ phần Chứng khoán Phố Wall có nền tảng tài chính lành mạnh với tỷ lệ đòn bẩy nợ cực thấp (0.75%), không có nợ vay ngân hàng và duy trì thanh khoản tốt với tiền gửi ngân hàng lớn. Tuy nhiên, lợi nhuận sau thuế giảm 29% từ 6.98 tỷ xuống 4.95 tỷ VND, EPS giảm từ 139 xuống 98 VND/cổ phiếu, phản ánh hoạt động môi giới và tư vấn bị ảnh hưởng bởi thị trường. Công ty có khoản ứng trước 44 tỷ cho bên liên kết và đầu tư 14 tỷ vào công ty liên kết, tổng chiếm ~10.8% tổng tài sản, cần theo dõi tiến độ dự án bất động sản. Công ty chưa nộp thuế TNDN lũy kế 11.83 tỷ do chuyển lỗ các năm trước. Điểm rủi ro quản trị ở mức trung bình thấp (4/10).'),
('WSS_2015_consolidated', 'WSS', 2015, 'consolidated', 'Giao dịch với ban lãnh đạo có giá trị nhỏ, không có dấu hiệu bất thường.', 'Nợ vay thấp, khả năng thanh toán tốt.', 'Không có hàng tồn kho.', 5, 'Công ty hoạt động ổn định nhưng lợi nhuận giảm. Ý kiến kiểm toán có ngoại trừ do vi phạm quy định cho phép khách hàng mua chứng khoán khi không đủ tiền.'),
('WSB_2025_consolidated', 'WSB', 2025, 'consolidated', 'Công ty có giao dịch lớn với công ty mẹ và các bên liên quan, bao gồm bán hàng, mua nguyên vật liệu và trả cổ tức. Các khoản phải thu từ bên liên quan không có bảo đảm và không lãi suất, cho thấy sự phụ thuộc vào công ty mẹ và rủi ro tập trung.', 'Công ty không có nợ vay ngân hàng lớn, chủ yếu là nợ phải trả thương mại ngắn hạn. Áp lực nợ vay thấp, khả năng thanh toán tốt.', 'Tồn kho bao gồm nguyên vật liệu, thành phẩm và sản phẩm dở dang. Có dự phòng cho hàng tồn kho chậm luân chuyển (dụng cụ dự phòng 744 triệu VNĐ), nhưng giá trị không lớn so với tổng tài sản.', 5, 'Công ty có sức khỏe tài chính tốt với lợi nhuận sau thuế tăng 18% so với năm trước, tỷ suất lợi nhuận gộp cải thiện, dòng tiền hoạt động kinh doanh dương. Không có nợ vay ngân hàng lớn và vốn chủ sở hữu cao. Tuy nhiên, doanh thu giảm do giảm giá nguyên liệu đầu vào. Triển vọng đầu tư trung bình đến tốt do ngành bia cạnh tranh nhưng công ty có thị phần ổn định và chi phí kiểm soát tốt.'),
('WSB_2023_consolidated', 'WSB', 2023, 'consolidated', 'Công ty có nhiều giao dịch thương mại lớn với Công ty mẹ (Tổng Công ty Cổ phần Bia - Rượu - Nước Giải Khát Sài Gòn) và các công ty trong hệ sinh thái SABECO. Các giao dịch này bao gồm bán thành phẩm, mua nguyên vật liệu, nhận cổ tức. Không có bằng chứng về giao dịch bất thường như cho vay không lãi suất hay chênh lệch giá lớn. Các khoản phải thu và phải trả với các bên liên quan đều không có đảm bảo và không tính lãi, đây là thông lệ thương mại bình thường.', 'Rủi ro nợ vay rất thấp. Công ty không có bất kỳ khoản vay ngân hàng (ngắn hạn hay dài hạn) nào. Nợ phải trả chủ yếu là thuế phải nộp, phải trả người bán và các khoản phải trả ngắn hạn khác. Công ty có lượng tiền mặt và tương đương tiền lớn (hơn 61 tỷ VNĐ) và đầu tư tài chính ngắn hạn (hơn 251 tỷ VNĐ) đảm bảo khả năng thanh toán cao.', 'Hàng tồn kho giảm so với đầu năm, chủ yếu do giảm thành phẩm. Dự phòng giảm giá hàng tồn kho được lập cho phụ tùng thay thế chậm luân chuyển và đã được hoàn nhập một phần trong năm. Dự án xây dựng cơ bản dở dang tăng mạnh do chi phí giải phóng mặt bằng cho dự án nhà máy mới, thể hiện kế hoạch mở rộng sản xuất trong tương lai.', 3, 'Tình hình tài chính của Công ty Cổ phần Bia Sài Gòn - Miền Tây rất lành mạnh. Doanh thu và lợi nhuận sau thuế năm 2023 tăng trưởng mạnh so với năm 2022. Công ty không sử dụng đòn bẩy tài chính (nợ vay), có cấu trúc vốn an toàn với vốn chủ sở hữu chiếm tỷ trọng lớn. Dòng tiền từ hoạt động kinh doanh tạo ra thuần dương lớn, cho thấy hoạt động sản xuất kinh doanh hiệu quả. Công ty có quan hệ thương mại mật thiết với tập đoàn mẹ SABECO nhưng các giao dịch này là minh bạch và có tính thương mại. Triển vọng đầu tư tích cực nhờ vào lợi thế từ hệ sinh thái SABECO và kế hoạch mở rộng nhà máy.'),
('WSB_2023_parent', 'WSB', 2023, 'parent', 'Công ty có giao dịch thương mại lớn với công ty mẹ (bán thành phẩm 365,903 tỷ VND, mua nguyên vật liệu 82,830 tỷ VND). Các giao dịch không có bảo đảm, không lãi suất, thu hồi/hoàn trả khi yêu cầu. Không có bằng chứng giao dịch bất thường về giá, nhưng phụ thuộc lớn vào công ty mẹ.', 'Công ty không có nợ vay ngân hàng (short-term và long-term loans = 0), áp lực nợ vay thấp. Các khoản nợ phải trả chủ yếu là thuế và phải trả người bán.', 'Hàng tồn kho có dự phòng giảm giá 731 triệu VND cho phụ tùng thay thế chậm luân chuyển. Phần lớn hàng tồn kho là nguyên vật liệu và thành phẩm cho hoạt động sản xuất bia, không có dự án xây dựng dở dang lớn.', 4, 'Công ty có sức khỏe tài chính tốt với lợi nhuận tăng trưởng, không có nợ vay, dòng tiền từ hoạt động kinh doanh mạnh. Tuy nhiên, phụ thuộc lớn vào công ty mẹ trong hoạt động kinh doanh. Điểm rủi ro quản trị ở mức trung bình do có nhiều giao dịch với các bên liên quan trong hệ sinh thái SABECO.'),
('WSB_2025_parent', 'WSB', 2025, 'parent', 'Công ty có nhiều giao dịch với công ty mẹ và các bên liên quan, bao gồm mua bán hàng hóa và dịch vụ. Các giao dịch này dường như được thực hiện theo giá thị trường và không có dấu hiệu bất thường, nhưng sự phụ thuộc vào công ty mẹ có thể ảnh hưởng đến tính độc lập kinh doanh.', 'Công ty không có nợ vay ngân hàng, nợ chủ yếu là phải trả thương mại và thuế phải nộp. Áp lực nợ thấp và công ty có khả năng thanh toán tốt.', 'Tồn kho bao gồm nguyên vật liệu và thành phẩm, có dự phòng cho phụ tùng chậm luân chuyển. Rủi ro tồn kho ở mức trung bình do dự phòng đã được trích lập.', 3, 'Công ty có lợi nhuận sau thuế tăng từ 80.7 tỷ lên 95.4 tỷ VND, doanh thu tài chính cao từ đầu tư và lãi tiền gửi. Tổng tài sản tăng nhẹ. Công ty có dòng tiền kinh doanh dương và trả cổ tức đều đặn. Triển vọng đầu tư tích cực dựa trên hiệu quả hoạt động và vị thế trong ngành bia.'),
('WSB_2024_parent', 'WSB', 2024, 'parent', 'Công ty có nhiều giao dịch với bên liên quan, đặc biệt là công ty mẹ (Tổng công ty Bia Rượu Nước giải khát Sài Gòn). Giao dịch mua bán hàng hóa, nguyên vật liệu và phân phối lợi nhuận từ công ty con có giá trị lớn, chiếm tỷ trọng cao trong hoạt động kinh doanh. Các giao dịch này được thực hiện theo giá thỏa thuận, không có lãi suất và không có tài sản thế chấp, phản ánh mối quan hệ thương mại nội bộ trong tập đoàn. Tuy nhiên, mức độ phụ thuộc vào công ty mẹ là đáng kể.', 'Công ty không có nợ vay ngân hàng, nguồn vốn chủ yếu từ vốn chủ sở hữu và các khoản phải trả thương mại ngắn hạn (nhà cung cấp, thuế, phúc lợi). Nợ ngắn hạn ở mức vừa phải (42.3 tỷ VND), nợ dài hạn chủ yếu là dự phòng trợ cấp thôi việc (3.2 tỷ VND). Áp lực trả nợ thấp, thanh khoản tốt với số dư tiền mặt và đầu tư ngắn hạn lớn.', 'Hàng tồn kho giảm nhẹ so với đầu năm, chủ yếu là nguyên vật liệu và bán thành phẩm phục vụ sản xuất bia. Có dự phòng cho công cụ dụng cụ chậm luân chuyển (740 triệu VND). Hàng tồn kho không có dấu hiệu ứ đọng lớn, không có dự án bất động sản tồn đọng.', 3, 'Công ty hoạt động trong ngành sản xuất kinh doanh bia, là công ty con của Tổng công ty Bia Sài Gòn. Doanh thu giảm nhẹ 3.4% so với năm trước, lợi nhuận sau thuế giảm 0.9%. Biên lợi nhuận gộp giảm từ 11.6% xuống 8.3%. Nguồn thu nhập tài chính lớn từ lãi tiền gửi và cổ tức từ công ty con, bù đắp cho biên lợi nhuận kinh doanh thu hẹp. Công ty có tình hình tài chính lành mạnh, không nợ vay, dòng tiền hoạt động kinh doanh dương mạnh. Cổ tức chi trả cao (tổng cộng 5000 đồng/cổ phiếu trong năm). Triển vọng ổn định nhưng phụ thuộc vào hoạt động của tập đoàn.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('WSB_2024_consolidated', 'WSB', 2024, 'consolidated', 'Giao dịch với công ty mẹ chiếm tỷ trọng lớn trong doanh thu và mua hàng, nhưng không có dấu hiệu giao dịch bất thường rõ ràng như cho vay không lãi suất hay chênh lệch giá lớn. Các giao dịch được thực hiện theo giá thị trường và được công khai đầy đủ.', 'Nợ vay chủ yếu là nợ ngắn hạn và không có khoản vay dài hạn đáng kể. Tổng nợ phải trả ở mức thấp so với tổng tài sản, áp lực nợ thấp, khả năng thanh toán tốt. Không có tài sản thế chấp nổi bật.', 'Hàng tồn kho giảm nhẹ so với năm trước, dự phòng giảm giá tồn kho không đáng kể. Hàng tồn kho bao gồm nguyên vật liệu, thành phẩm và chi phí sản xuất dở dang, không có dấu hiệu ứ đọng lớn.', 3, 'Công ty có tình hình tài chính khỏe mạnh với tỷ lệ nợ thấp, dòng tiền hoạt động kinh doanh dương và lợi nhuận ổn định. Doanh thu giảm nhẹ nhưng biên lợi nhuận gộp vẫn duy trì. Công ty phụ thuộc vào công ty mẹ cho doanh thu và mua hàng, nhưng không có rủi ro quản trị nghiêm trọng. Triển vọng đầu tư ổn định.'),
('WSB_2022_consolidated', 'WSB', 2022, 'consolidated', 'Công ty có mối quan hệ kinh doanh mật thiết với công ty mẹ và nhiều bên liên quan khác, thể hiện qua doanh số bán hàng và mua hàng lớn. Các giao dịch chủ yếu là thương mại bình thường trong chuỗi giá trị ngành bia, không có thông tin về lãi suất ưu đãi hay điều kiện bất thường. Tuy nhiên, mức độ tập trung cao vào công ty mẹ có thể tạo rủi ro nếu hoạt động của công ty mẹ bị ảnh hưởng.', 'Công ty không có nợ vay ngân hàng tồn đọng. Nợ phải trả ngắn hạn chủ yếu là thuế phải nộp (77,6 tỷ VND) và phải trả người bán. Nợ dài hạn rất nhỏ (6,4 tỷ VND) là dự phòng trợ cấp thôi việc. Chi phí lãi vay chỉ 143 triệu VND. Công ty có vị thế thanh khoản tốt với tài sản ngắn hạn (363,9 tỷ VND) lớn hơn nhiều nợ ngắn hạn.', 'Hàng tồn kho tăng mạnh từ 54,1 tỷ VND lên 94,8 tỷ VND, đặc biệt nguyên vật liệu tăng từ 18 tỷ lên 40,3 tỷ và thành phẩm tăng từ 13,4 tỷ lên 27,2 tỷ. Tồn kho dở dang (chi phí sản xuất dở dang) ở mức 22,7 tỷ VND. Có dự phòng giảm giá 1,6 tỷ VND cho phụ tùng thay thế chậm luân chuyển. Sự gia tăng tồn kho trong bối cảnh doanh thu giảm 4,4% cho thấy khả năng ứ đọng hàng hóa, đặc biệt khi giá nguyên vật liệu tăng do áp lực lạm phát.', 3, 'Công ty Cổ phần Bia Sài Gòn – Miền Tây hoạt động trong ngành bia, năm 2022 doanh thu giảm 4,4% so với cùng kỳ, lợi nhuận sau thuế giảm 26,4% do giá nguyên vật liệu tăng. Hàng tồn kho tăng mạnh, nợ phải trả giảm. Công ty có vị thế tài chính vững mạnh với vốn chủ sở hữu 717,4 tỷ VND, không có nợ vay ngân hàng, dòng tiền kinh doanh dương 36,6 tỷ VND. Tuy nhiên, sự phụ thuộc lớn vào công ty mẹ và áp lực từ lạm phát là những rủi ro cần theo dõi. Triển vọng trung hạn phụ thuộc vào khả năng kiểm soát chi phí và phục hồi nhu cầu tiêu dùng.'),
('WSB_2022_parent', 'WSB', 2022, 'parent', 'Các giao dịch với bên liên quan chủ yếu là mua bán hàng hóa, nguyên vật liệu và phân phối lợi nhuận trong nội bộ tập đoàn Sài Gòn, không có dấu hiệu bất thường rõ ràng. Các khoản phải thu từ công ty mẹ và công ty con không có lãi suất và không có tài sản đảm bảo, điều này phổ biến trong nội bộ tập đoàn nhưng vẫn tiềm ẩn rủi ro thanh toán.', 'Công ty có nợ ngắn hạn 43.46 tỷ VND và nợ dài hạn 3.62 tỷ VND, chủ yếu là thuế phải nộp và phải trả người bán. Công ty có khoản vay ngắn hạn 7.2 tỷ VND trong năm đã trả hết. Với lượng tiền mặt và đầu tư ngắn hạn lớn (gần 179 tỷ VND), thanh khoản tốt, áp lực nợ không cao.', 'Hàng tồn kho có dự phòng giảm giá 965 triệu VND cho phụ tùng thay thế chậm luân chuyển. Xây dựng cơ bản dở dang chỉ còn 61 triệu VND, cho thấy dự án đã cơ bản hoàn thành. Rủi ro tồn kho ở mức thấp.', 3, 'Công ty có tình hình tài chính ổn định, thanh khoản tốt, nợ vay thấp. Tuy nhiên, doanh thu và lợi nhuận giảm so với năm trước do áp lực lạm phát tăng chi phí đầu vào. Công ty có mối quan hệ kinh doanh mật thiết với công ty mẹ và các công ty trong tập đoàn, tập trung vào sản xuất và kinh doanh bia. Triển vọng phụ thuộc vào tình hình thị trường và hoạt động của tập đoàn.'),
('WSB_2021_consolidated', 'WSB', 2021, 'consolidated', 'Công ty có mối quan hệ chặt chẽ với công ty mẹ (Tổng Công ty Cổ phần Bia - Rượu - Nước Giải Khát Sài Gòn) và nhiều công ty liên kết/con trong hệ sinh thái Sabeco. Giao dịch mua bán hàng hóa, nguyên vật liệu với công ty mẹ là rất lớn (hơn 1.486 tỷ đồng doanh thu bán hàng). Các giao dịch này được ghi nhận không có lãi suất và không đảm bảo. Mặc dù đây là giao dịch thương mại bình thường trong nội bộ tập đoàn, nhưng mức độ phụ thuộc vào công ty mẹ là cao, tạo rủi ro về giá chuyển nhượng và khả năng thanh toán.', 'Công ty không có các khoản vay nợ ngân hàng truyền thống. Nợ chủ yếu là phải trả người bán, thuế và các khoản phải trả khác. Điều này cho thấy công ty có cấu trúc tài chính an toàn, không phụ thuộc vào đòn bẩy nợ, giảm áp lực trả nợ và lãi vay. Tuy nhiên, thuế phải nộp nhà nước chiếm tỷ trọng lớn (hơn 101 tỷ đồng), cần được quản lý tốt.', 'Hàng tồn kho giảm từ 63.5 tỷ (đầu năm) xuống 54.1 tỷ (cuối năm), với dự phòng giảm giá 1.2 tỷ cho phụ tùng thay thế chậm luân chuyển. Chi phí sản xuất kinh doanh dở dang cũng giảm đáng kể. Điều này cho thấy công ty đã quản lý tồn kho hiệu quả, giảm ứ đọng. Dự án xây dựng cơ bản dở dang tăng mạnh (từ 0.7 tỷ lên 13.4 tỷ) cho thấy hoạt động đầu tư mở rộng, đây là cơ hội nhưng cũng là rủi ro nếu dự án không hiệu quả.', 3, 'Bia Sài Gòn - Miền Tây là công ty con thuộc hệ thống Sabeco, hoạt động trong ngành sản xuất bia. Sức khỏe tài chính vững mạnh với lợi nhuận sau thuế 97.7 tỷ, tỷ suất lợi nhuận gộp 14.3%. Công ty có cấu trúc tài sản an toàn (tiền mặt và đầu tư ngắn hạn lớn), không vay nợ ngân hàng, dòng tiền hoạt động kinh doanh dương mạnh (155.9 tỷ). Tuy nhiên, doanh thu giảm so với năm trước do ảnh hưởng Covid-19. Điểm rủi ro chính là sự phụ thuộc vào công ty mẹ trong giao dịch mua bán. Triển vọng đầu tư tích cực nhờ vị thế vững chắc trong ngành, nền tảng tài chính lành mạnh và khả năng sinh lời ổn định.'),
('WSB_2021_parent', 'WSB', 2021, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm công ty mẹ, công ty con và công ty liên kết. Các giao dịch chủ yếu là mua bán hàng hóa, nguyên vật liệu và trả cổ tức. Khoản phải thu từ công ty mẹ không có đảm bảo và không hưởng lãi, cho thấy có thể có rủi ro chiếm dụng vốn, nhưng giá trị không lớn so với quy mô công ty. Nhìn chung, giao dịch bên liên quan tuân theo điều kiện thị trường và không có dấu hiệu bất thường rõ ràng.', 'Công ty không có nợ vay ngân hàng, nợ phải trả chủ yếu là phải trả người bán và thuế phải nộp. Điều này cho thấy áp lực nợ vay thấp và khả năng thanh toán tốt, không có rủi ro nợ cao.', 'Hàng tồn kho có dự phòng giảm giá nhưng không đáng kể. Xây dựng cơ bản dở dang tăng mạnh trong năm, nhưng không có thông tin về dự án cụ thể hay rủi ro ứ đọng. Rủi ro tồn kho ở mức trung bình do biến động trong sản xuất kinh doanh.', 3, 'Công ty Bia Sài Gòn - Miền Tây có sức khỏe tài chính ổn định với tài sản dồi dào và không có nợ vay. Lợi nhuận năm 2021 giảm do ảnh hưởng của đại dịch Covid-19 đến doanh thu, nhưng công ty đã kiểm soát chi phí hiệu quả. Dòng tiền từ hoạt động kinh doanh dương, và công ty có khả năng thanh toán tốt. Triển vọng đầu tư trung bình, phụ thuộc vào sự phục hồi của ngành bia rượu sau đại dịch.'),
('WSS_2019_consolidated', 'WSS', 2019, 'consolidated', 'Công ty có đầu tư dài hạn vào 2 công ty liên kết với tổng vốn 19,75 tỷ VND (Công ty Đô thị Phố Wall 14%, Công ty Khoáng sản Cao Bằng 10.99%). Có khoản ứng trước mua nhà 72 tỷ cho Bà Nguyễn Thanh Bích Hà và 45 tỷ cho Công ty An Sinh thuê văn phòng. Thu nhập ban lãnh đạo năm 2019 khoảng 1,2 tỷ VND. Không phát hiện giao dịch bất thường đáng ngờ (cho vay không lãi suất, mua bán chênh lệch lớn) với các bên liên quan.', 'Công ty có nợ vay ngắn hạn duy nhất 44 tỷ VND tại Ngân hàng TMCP Bắc Á với lãi suất thả nổi 7,4%/năm cộng biên độ 1,5%. Tài sản thế chấp là tiền gửi có kỳ hạn trị giá ~48,5 tỷ VND. Công ty có tiền và tương đương tiền 75,9 tỷ VND, đủ khả năng thanh toán nợ. Áp lực nợ thấp do tỷ lệ nợ/vốn chủ sở hữu chỉ ~9,5%.', 'Công ty chứng khoán không có hàng tồn kho và dự án xây dựng dở dang. Rủi ro tồn kho không áp dụng. Rủi ro chính là danh mục đầu tư tài sản tài chính FVTPL bị đánh giá giảm mạnh 72,4 tỷ VND trong năm.', 3, 'Công ty lỗ nặng năm 2019 (-79,9 tỷ VND) do hoạt động tự doanh kém hiệu quả: lỗ bán chứng khoán FVTPL 16,8 tỷ, lỗ đánh giá lại FVTPL 72,4 tỷ, và lỗ thoái vốn 15,52 tỷ từ chuyển nhượng cổ phần Công ty Đầu tư Thương mại Quốc tế. Tuy nhiên, nền tảng tài chính vẫn vững: vốn chủ sở hữu 512 tỷ VND, nợ phải trả chỉ 48,6 tỷ VND, tỷ lệ nợ/vốn chủ sở hữu ~9,5%. Tiền và tương đương tiền đạt 75,9 tỷ VND đảm bảo thanh khoản. Công ty đã tuân thủ Nghị định 71/2017 về quản trị công ty và không vi phạm nghĩa vụ công bố thông tin. Triển vọng phụ thuộc lớn vào diễn biến thị trường chứng khoán và khả năng phục hồi hoạt động tự doanh.'),
('WSB_2020_consolidated', 'WSB', 2020, 'consolidated', 'Công ty có giao dịch lớn với công ty mẹ (Tổng Công ty CP Bia - Rượu - NGK Sài Gòn) bao gồm bán thành phẩm 1,544 tỷ VND và mua nguyên vật liệu 422 tỷ VND. Các khoản phải thu từ công ty mẹ 15 tỷ VND không có đảm bảo và không hưởng lãi suất, cho thấy mức độ phụ thuộc lớn vào công ty mẹ. Ngoài ra còn giao dịch với nhiều bên liên quan khác trong hệ sinh thái Sabeco.', 'Công ty đã trả toàn bộ nợ ngắn hạn từ Vietinbank (144.97 tỷ VND) trong năm 2020. Không còn dư nợ vay tính đến 31/12/2020. Chi phí lãi vay giảm mạnh từ 6.27 tỷ xuống 3.63 tỷ VND. Vị thế tiền mặt mạnh với 64.3 tỷ VND tiền và tương đương tiền. Không có áp lực nợ vay đáng kể.', 'Có khoản phụ tùng thay thế chậm luân chuyển trị giá 1,777 triệu VND đã trích lập dự phòng. Dự án xây dựng cơ bản dở dang giảm mạnh từ 7,922 triệu VND xuống còn 725 triệu VND, cho thấy các dự án đã được hoàn thành hoặc chuyển sang TSCĐ. Hàng tồn kho giảm từ 81.9 tỷ xuống 63.5 tỷ VND, phản ánh doanh thu giảm do ảnh hưởng Covid-19.', 4, 'Công ty CP Bia Sài Gòn - Miền Tây chịu tác động nặng nề từ đại dịch Covid-19 và Nghị định 100/2019/NĐ-CP về kiểm soát đồ uống có cồn, khiến doanh thu giảm 20.6% và lợi nhuận sau thuế giảm 29.1%. Tuy nhiên, tình hình tài chính vẫn ổn định với vị thế tiền mặt mạnh, đã thanh toán hết nợ vay ngắn hạn, giảm đáng kể chi phí lãi vay. Tỷ suất lợi nhuận gộp duy trì ở mức 16.75%. Công ty con Sóc Trăng được hưởng ưu đãi thuế 10%. Công ty tiếp tục chi trả cổ tức ổn định (5,000 VND/cổ phiếu). Sức khỏe tài chính ở mức khá nhưng triển vọng tăng trưởng phụ thuộc vào phục hồi ngành bia rượu hậu Covid.'),
('WSB_2018_consolidated', 'WSB', 2018, 'consolidated', 'Công ty có giao dịch lớn với công ty mẹ, bao gồm bán hàng và mua nguyên vật liệu với giá trị cao, có thể ảnh hưởng đến tính công bằng về giá. Các giao dịch với bên liên quan khác nhỏ hơn nhưng vẫn đáng chú ý. Không có thông tin về lãi suất hoặc đảm bảo, có thể tiềm ẩn rủi ro về quản trị.', 'Nợ vay ngắn hạn chủ yếu từ Vietinbank với lãi suất thả nổi và được đảm bảo bằng tài sản cố định. Áp lực nợ vay ở mức trung bình, với tỷ lệ nợ trên tổng tài sản khoảng 36.4%. Thời hạn vay ngắn có thể gây rủi ro thanh khoản nếu dòng tiền không ổn định.', 'Hàng tồn kho tăng từ 58.3 tỷ VND lên 73.4 tỷ VND trong năm, cho thấy có thể có hàng tồn kho dở dang hoặc tích lũy thành phẩm. Cần theo dõi khả năng tiêu thụ và nguy cơ lỗi mốt trong ngành bia.', 6, 'Công ty có kết quả kinh doanh ổn định với lợi nhuận gộp tỷ lệ khoảng 17.5%. Tuy nhiên, phụ thuộc lớn vào công ty mẹ trong hoạt động mua bán, nợ vay ngắn hạn với lãi suất biến động và tăng trưởng tồn kho có thể là rủi ro. Quản trị ở mức trung bình, cần cải thiện minh bạch trong giao dịch liên quan.'),
('WSB_2018_parent', 'WSB', 2018, 'parent', 'Doanh thu bán hàng cho công ty mẹ (Tổng Công ty CP Bia-Rượu-Nước Giải Khát Sài Gòn) chiếm tỷ trọng áp đảo (~97% doanh thu bán thành phẩm), tạo sự phụ thuộc lớn vào bên liên quan. Các khoản phải thu từ công ty mẹ tăng mạnh từ 6,2 tỷ lên 12,7 tỷ VND, cho thấy khả năng thu hồi nợ có thể bị ảnh hưởng bởi chính sách thanh toán của công ty mẹ. Công ty cũng cho vay không lãi suất và cho mượn vật tư với công ty con (Sóc Trăng) và các bên liên quan khác. Tổng giao dịch mua bán với hệ sinh thái Sabeco rất lớn, tiềm ẩn rủi ro giá chuyển nhượng có thể không phản ánh giá thị trường.', 'Nợ vay ngắn hạn trong năm đã được tất toán hoàn toàn (51,7 tỷ VND vay và trả trong cùng năm, lãi suất 5%/năm). Công ty không có nợ dài hạn. Nợ phải trả chủ yếu là phải trả người bán (13,2 tỷ VND) và thuế phải nộp (28,6 tỷ VND). Áp lực nợ vay thấp, thanh khoản tốt với tiền và tương đương tiền đạt 16 tỷ VND.', 'Hàng tồn kho tăng từ 29,8 tỷ lên 34,9 tỷ VND (+17%), trong đó thành phẩm tăng mạnh từ 3,0 tỷ lên 10,1 tỷ VND (~234%), có thể do tích trữ hàng cuối năm. Hàng tồn kho không có dự phòng giảm giá, cho thấy công ty đánh giá không có rủi ro giảm giá. Chi phí SXKD dở dang 10,9 tỷ VND phản ánh quy trình sản xuất bia đang diễn ra, không có dấu hiệu ứ đọng nghiêm trọng.', 6, 'Công ty có kết quả kinh doanh ổn định với doanh thu thuần 347 tỷ VND và lợi nhuận sau thuế 118 tỷ VND trong năm 2018. Biên lợi nhuận gộp đạt ~21,5%. Công ty có cấu trúc tài chính lành mạnh, không có nợ vay dài hạn, thanh khoản tốt. Tuy nhiên, doanh thu phụ thuộc gần như hoàn toàn vào công ty mẹ (~97% doanh thu), tạo rủi ro tập trung khách hàng lớn. Công ty chi trả cổ tức lớn (116 tỷ VND trong năm 2018), phản ánh chính sách chia lợi nhuận hào phóng. Điểm đáng lưu ý là nhiều giao dịch với các bên liên quan trong hệ sinh thái Sabeco, cần đánh giá tính công bằng về giá chuyển nhượng.'),
('WSB_2017_consolidated', 'WSB', 2017, 'consolidated', 'Doanh nghiệp có giao dịch lớn với công ty mẹ (Tổng Công ty Cổ phần Bia - Rượu - Nước Giải khát Sài Gòn), chiếm tỷ trọng cao trong doanh thu bán hàng và chi phí mua hàng hóa/dịch vụ. Giao dịch bán tài sản cố định và mua cổ phần với các bên liên quan khác cũng đáng lưu ý. Cần đánh giá tính công bằng của giá cả và tính minh bạch trong các giao dịch này.', 'Nợ vay chủ yếu là ngắn hạn (136,55 tỷ VND) với lãi suất thả nổi, được đảm bảo bằng toàn bộ tài sản cố định hình thành từ dự án Nhà máy Bia Sài Gòn - Sóc Trăng. Công ty đã trả hết nợ dài hạn. Áp lực nợ vay ở mức kiểm soát nhờ dòng tiền hoạt động kinh doanh mạnh (149 tỷ VND năm 2017), nhưng cần theo dõi biến động lãi suất.', 'Hàng tồn kho trị giá 58,34 tỷ VND, bao gồm nguyên vật liệu, thành phẩm, chi phí sản xuất kinh doanh dở dang. Không có dự phòng giảm giá tồn kho, cho thấy hàng tồn kho được đánh giá ở mức hợp lý. Tuy nhiên, tồn kho giảm so với năm trước, có thể do tiêu thụ tốt hoặc quản lý tồn kho hiệu quả.', 5, 'Doanh nghiệp có kết quả kinh doanh tích cực: lợi nhuận sau thuế tăng 10,85% so với năm trước, sản lượng tiêu thụ tăng 5,53%. Dòng tiền từ hoạt động kinh doanh dương mạnh, nợ vay giảm đáng kể. Điểm mạnh là biên lợi nhuận gộp ổn định (~17,6%) và chi phí lãi vay giảm. Rủi ro chính là sự phụ thuộc lớn vào công ty mẹ và giao dịch với các bên liên quan, cùng với nợ vay ngắn hạn lãi suất thả nổi. Triển vọng trung bình, phù hợp cho nhà đầu tư thận trọng.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('WSB_2016_parent', 'WSB', 2016, 'parent', 'Doanh thu bán hàng của Công ty phụ thuộc lớn vào công ty mẹ (Tổng Công ty CP Bia-Rượu-Nước Giải khát Sài Gòn) chiếm khoảng 95% tổng doanh thu. Công ty cũng mua nguyên vật liệu lớn từ công ty mẹ. Các giao dịch mua bán với bên liên quan có quy mô lớn, tạo ra rủi ro về tính độc lập và giá chuyển nhượng không theo giá thị trường, tuy nhiên không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất.', 'Công ty chỉ có khoản vay ngắn hạn tín chấp 87,6 tỷ VND từ VietinBank với lãi suất ưu đãi (4.3-4.6%/năm) và thời hạn ngắn 6 tháng. Áp lực nợ vay không cao do lãi suất thấp, không có nợ dài hạn. Tuy nhiên, công ty cần đảm bảo khả năng tái tục khoản vay ngắn hạn này.', 'Hàng tồn kho chủ yếu là nguyên liệu, thành phẩm và công cụ dụng cụ, không có dự án bất động sản dở dang. Giá trị tồn kho giảm nhẹ so với năm trước và không trích lập dự phòng giảm giá, cho thấy rủi ro tồn kho thấp.', 4, 'Sức khỏe tài chính của Công ty tương đối ổn định với dòng tiền hoạt động kinh doanh dương mạnh (129 tỷ VND). Doanh thu và lợi nhuận giảm nhẹ so với năm trước. Công ty có khoản đầu tư lớn vào công ty con và liên kết. Cơ cấu vốn chủ sở hữu lớn, không có nợ dài hạn. Tuy nhiên, sự phụ thuộc lớn vào công ty mẹ về doanh thu và mua hàng là điểm cần lưu ý. Triển vọng đầu tư trung bình, phù hợp với nhà đầu tư tìm kiếm cổ tức ổn định (cổ tức chi trả cao).'),
('WSB_2017_parent', 'WSB', 2017, 'parent', 'Công ty có giao dịch lớn với bên liên quan, đặc biệt là công ty mẹ (Tổng Công ty Cổ phần Bia - Rượu - Nước Giải khát Sài Gòn) và công ty con (Công ty TNHH MTV Bia Sài Gòn Sóc Trăng). Giao dịch mua bán hàng hóa chiếm tỷ trọng doanh thu và giá vốn cao. Tuy nhiên, không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn bất thường.', 'Áp lực nợ vay thấp do Công ty đã thanh toán toàn bộ nợ vay ngắn hạn trong năm 2017. Tài sản thế chấp chính là toàn bộ TSCĐ của Nhà máy Bia Sài Gòn – Cần Thơ. Dòng tiền hoạt động kinh doanh dương, khả năng thanh toán tốt.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và thành phẩm, không có dự án bất động sản. Tồn kho giảm nhẹ so với năm trước, không có dấu hiệu ứ đọng lớn. Rủi ro tồn kho ở mức thấp.', 3, 'Công ty có kết quả kinh doanh tăng trưởng tốt, lợi nhuận sau thuế tăng 22.45% so với năm trước nhờ sản lượng tiêu thụ tăng và chi phí lãi vay giảm. Nợ vay đã được trả hết, giảm đáng kể rủi ro tài chính. Tuy nhiên, tỷ trọng giao dịch với bên liên quan cao, đặc biệt với công ty mẹ, cần theo dõi tính độc lập trong hoạt động kinh doanh. Triển vọng đầu tư ổn định trong ngành bia.'),
('WSB_2015_consolidated', 'WSB', 2015, 'consolidated', 'Doanh nghiệp có mối quan hệ chặt chẽ với công ty mẹ (Tổng Công ty Cổ phần Bia – Rượu – Nước Giải khát Sài Gòn - sở hữu 51% vốn) và các công ty liên kết, dẫn đến tỷ trọng giao dịch với bên liên quan rất lớn, đặc biệt trong mua bán hàng hóa và dịch vụ. Đáng chú ý có khoản phải thu thuế TTĐB hộ công ty mẹ lên đến 131,5 tỷ VND, tiềm ẩn rủi ro về khả năng thu hồi nếu công ty mẹ không hoàn trả.', 'Tổng nợ vay (ngắn hạn và dài hạn) là 442,97 tỷ VND, chiếm tỷ trọng đáng kể trong tổng nguồn vốn. Nợ vay tăng mạnh so với năm trước. Các khoản vay dài hạn được đảm bảo bằng toàn bộ tài sản cố định là các dự án nhà máy lớn. Công ty cũng vay ngắn hạn bổ sung vốn lưu động với lãi suất biến động.', 'Giá trị hàng tồn kho giảm mạnh từ 94 tỷ xuống 61,5 tỷ VND, cho thấy khả năng quản lý tồn kho được cải thiện hoặc doanh thu tăng. Không có dự phòng giảm giá tồn kho, cho thấy hàng tồn kho được đánh giá là có chất lượng và khả năng tiêu thụ tốt.', 6, 'Công ty có kết quả kinh doanh ổn định với doanh thu thuần 826 tỷ VND và lợi nhuận sau thuế 95,5 tỷ VND. Tuy nhiên, doanh nghiệp phụ thuộc lớn vào công ty mẹ và các bên liên quan trong chuỗi cung ứng và phân phối. Rủi ro chính nằm ở khoản phải thu thuế TTĐB lớn từ công ty mẹ chưa được quyết định rõ ràng, và áp lực nợ vay tăng cao. Ý kiến kiểm toán ngoại trừ về thuế TTĐB cũng là điểm cần lưu ý.'),
('WSB_2016_consolidated', 'WSB', 2016, 'consolidated', 'Doanh nghiệp có giao dịch lớn với công ty mẹ (doanh thu bán hàng chiếm tỷ trọng cao). Tuy nhiên, không phát hiện giao dịch bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay ngắn hạn và dài hạn tổng cộng 251.5 tỷ VND, lãi suất ở mức thấp (4.3-6.5%/năm). Có tài sản thế chấp là tài sản hình thành từ dự án nhà máy bia Sóc Trăng. Áp lực nợ ở mức trung bình.', 'Hàng tồn kho tăng nhẹ từ 61.5 tỷ lên 66.4 tỷ VND, bao gồm nguyên liệu, thành phẩm và sản phẩm dở dang. Không có dự phòng giảm giá, rủi ro tồn kho thấp.', 5, 'Doanh nghiệp có kết quả kinh doanh tốt với lợi nhuận sau thuế tăng 14.64%. Phụ thuộc lớn vào công ty mẹ về doanh thu. Nợ vay được kiểm soát, tài sản cố định lớn. Triển vọng đầu tư ổn định.'),
('WCS_2025_consolidated', 'WCS', 2025, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là cung cấp dịch vụ và phải thu thương mại, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty không có nợ vay ngân hàng, chỉ có các khoản phải trả thương mại và phải trả khác, áp lực nợ vay thấp.', 'Hàng tồn kho rất thấp (nguyên liệu, vật liệu), rủi ro ứ đọng thấp. Dự án xây dựng dở dang là đầu tư mở rộng, không có dấu hiệu đình trệ.', 2, 'Công ty có sức khỏe tài chính tốt với lợi nhuận tăng trưởng 10,89% so với cùng kỳ, không có nợ vay, dòng tiền hoạt động mạnh. Triển vọng đầu tư tích cực nhờ vào vị thế kinh doanh ổn định và tăng trưởng doanh thu.'),
('WCS_2024_consolidated', 'WCS', 2024, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là cung cấp dịch vụ vận tải và trả cổ tức cho công ty mẹ. Giá trị giao dịch chiếm tỷ trọng nhỏ trong tổng doanh thu, không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty không có nợ vay (vay và nợ thuê tài chính đều bằng 0). Các khoản phải trả chủ yếu là phải trả người lao động và thuế. Áp lực nợ vay thấp, khả năng thanh toán tốt với lượng tiền mặt và đầu tư ngắn hạn dồi dào.', 'Hàng tồn kho có giá trị nhỏ và không có dự phòng giảm giá. Dự án xây dựng dở dang có giá trị vừa phải và đã được chuyển giao một phần sang tài sản cố định, không có dấu hiệu ứ đọng.', 2, 'Công ty có kết quả kinh doanh tăng trưởng tốt, không sử dụng đòn bẩy tài chính, tài sản lưu động cao và cổ tức trả đều đặn. Sức khỏe tài chính vững mạnh, triển vọng đầu tư tích cực.'),
('WCS_2023_consolidated', 'WCS', 2023, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là giao dịch thương mại thông thường như cung cấp dịch vụ và chia cổ tức, không có dấu hiệu bất thường hay giao dịch giá trị không hợp lý.', 'Công ty không có nợ vay có lãi suất, chỉ có các khoản phải trả thương mại và phải trả khác. Áp lực nợ thấp, khả năng thanh toán tốt với tài sản thanh khoản dồi dào.', 'Hàng tồn kho quy mô nhỏ, chủ yếu là nguyên vật liệu và hàng hoá phục vụ hoạt động kinh doanh. Các dự án xây dựng dở dang đang trong tiến độ bình thường, không có rủi ro ứ đọng hay chậm trễ.', 3, 'Tình hình tài chính lành mạnh, lợi nhuận sau thuế tăng trưởng mạnh 73.36% so với cùng kỳ, không có nợ vay, dòng tiền hoạt động kinh doanh dương mạnh. Công ty tập trung vào hoạt động kinh doanh bến xe có doanh thu ổn định và triển vọng tích cực.'),
('WCS_2020_consolidated', 'WCS', 2020, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là cung cấp dịch vụ vận tải và chia cổ tức, không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Các khoản phải thu, phải trả với bên liên quan có giá trị nhỏ và giảm dần.', 'Công ty không có nợ vay ngân hàng, nợ phải trả chủ yếu là nợ thương mại và cổ tức phải trả. Áp lực nợ thấp, khả năng thanh toán tốt. Nợ dài hạn chủ yếu là ký quỹ từ các công ty vận tải trong tập đoàn.', 'Hàng tồn kho giá trị rất nhỏ (60 triệu VND), không có dự phòng. Dự án xây dựng dở dang giảm mạnh từ 6,3 tỷ xuống 600 triệu VND, cho thấy các dự án đã được hoàn thành và chuyển giao vào tài sản cố định, không có dấu hiệu ứ đọng.', 3, 'Công ty Bến Xe Miền Tây có tình hình tài chính lành mạnh với lợi nhuận cao, dòng tiền mạnh từ hoạt động kinh doanh và đầu tư. Không có nợ vay tài chính, nợ phải trả thấp. Công ty là thành viên của tập đoàn nhà nước (Samco), quản trị minh bạch. Rủi ro thấp, triển vọng ổn định.'),
('WCS_2021_consolidated', 'WCS', 2021, 'consolidated', 'Công ty có giao dịch với các bên liên quan bao gồm công ty mẹ và công ty cùng tập đoàn, chủ yếu là cung cấp dịch vụ và chia cổ tức. Các giao dịch này có vẻ bình thường, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty không có nợ vay ngân hàng vào năm 2021, chỉ có các khoản phải trả nhà cung cấp và người lao động. Áp lực nợ vay thấp, khả năng thanh toán tốt với lượng tiền mặt dồi dào.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu với giá trị thấp. Các dự án xây dựng dở dang có quy mô nhỏ, không bị ứ đọng, rủi ro thấp.', 3, 'Công ty có tình hình tài chính ổn định, với lượng tiền mặt lớn và không có nợ vay. Tuy nhiên, lợi nhuận giảm mạnh 79.23% so với năm trước do ảnh hưởng của dịch bệnh Covid-19, khiến doanh thu từ hoạt động kinh doanh chính sụt giảm. Công ty có thể thanh toán tốt các nghĩa vụ tài chính, nhưng triển vọng phụ thuộc vào sự phục hồi của ngành vận tải hành khách sau đại dịch.'),
('WSS_2021_consolidated', 'WSS', 2021, 'consolidated', 'Công ty có khoản ứng trước lớn 128 tỷ VNĐ cho Công ty Cổ phần An Sinh để thuê văn phòng 40 năm (hợp đồng 02/AS-HĐVP), đã quá hạn bàn giao và phải tính lãi chậm giao 2,7 tỷ VNĐ. Các giao dịch thù lao với thành viên HĐQT, Ban Kiểm soát và Ban Tổng Giám đốc ở mức hợp lý, tổng cộng khoảng 1,4 tỷ VNĐ/năm. Không phát hiện giao dịch bất thường với công ty sân sau hay cho vay không lãi suất.', 'Công ty không có nợ vay ngân hàng hay trái phiếu phát hành, nợ phải trả chủ yếu là các khoản phải trả hoạt động ngắn hạn (5,2 tỷ VNĐ), tỷ lệ nợ trên vốn chủ sở hữu rất thấp (~1%). Áp lực nợ vay gần như không có, thanh khoản đảm bảo tốt. Tuy nhiên, Công ty có khoản đầu tư dài hạn vào các công ty con/liên kết (19,75 tỷ VNĐ) chưa được đánh giá lại theo giá trị hợp lý.', 'Công ty chứng khoán không có hàng tồn kho truyền thống. Các khoản cho vay margin và ứng trước tiền bán (27,09 tỷ VNĐ) đã trích lập dự phòng suy giảm giá trị 8,64 tỷ VNĐ. Danh mục FVTPL có mức lỗ đánh giá lại chưa thực hiện lớn (-27,6 tỷ VNĐ), cho thấy rủi ro biến động giá trị thị trường đáng kể.', 3, 'Công ty Cổ phần Chứng khoán Phố Wall (WSS) có quy mô nhỏ với vốn điều lệ 503 tỷ VNĐ, tổng tài sản 537 tỷ VNĐ. Công ty có cơ cấu tài chính lành mạnh: không có nợ vay, tỷ lệ nợ rất thấp. Tuy nhiên, lợi nhuận sau thuế giảm từ 10,7 tỷ xuống 9,0 tỷ VNĐ, EPS giảm từ 213 xuống 178 đồng. Lỗ chưa thực hiện từ đánh giá lại danh mục FVTPL lên tới 27,6 tỷ VNĐ là rủi ro lớn. Khoản ứng trước 128 tỷ VNĐ cho Công ty An Sinh chiếm tỷ trọng lớn trong tài sản ngắn hạn và đã trễ tiến độ bàn giao. Công ty có lãi đã thực hiện lũy kế 48,1 tỷ VNĐ nhưng chưa chia cổ tức. Triển vọng đầu tư ở mức trung bình, phù hợp với nhà đầu tư thận trọng.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('WCS_2019_consolidated', 'WCS', 2019, 'consolidated', 'Công ty có giao dịch với các bên liên quan như công ty mẹ, cùng tập đoàn và liên kết, bao gồm cho vay, cung cấp dịch vụ và mua hàng. Các giao dịch này có vẻ theo giá thị trường và không có dấu hiệu bất thường, nhưng cần theo dõi vì khối lượng giao dịch lớn với công ty mẹ.', 'Công ty không có nợ vay ngân hàng, chỉ có các khoản phải trả người bán và phải trả khác. Áp lực nợ vay thấp, khả năng thanh toán tốt nhờ tiền mặt và đầu tư ngắn hạn dồi dào. Không có tài sản thế chấp nổi bật vì không có nợ vay.', 'Hàng tồn kho giá trị thấp, chủ yếu là nguyên vật liệu và hàng hóa, không có dự phòng. Các dự án xây dựng dở dang có tiến độ, một số đã hoàn thành và chuyển sang tài sản cố định, không có dấu hiệu ứ đọng lớn.', 3, 'Công ty có sức khỏe tài chính tốt với doanh thu ổn định, lợi nhuận cao và dòng tiền mạnh. Đầu tư tài chính ngắn hạn lớn mang lại thu nhập tài chính đáng kể. Không có nợ vay, giảm rủi ro tài chính. Tuy nhiên, phụ thuộc vào hoạt động kinh doanh bến xe và giao dịch với các bên liên quan trong tập đoàn. Triển vọng đầu tư tích cực trong ngắn hạn, nhưng cần theo dõi tăng trưởng dài hạn.'),
('WCS_2017_consolidated', 'WCS', 2017, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là thương mại (cung cấp dịch vụ, mua hàng) và cho vay có lãi suất thị trường. Khoản cho vay 30 tỷ VND cho công ty mẹ có lãi suất 6.5%/năm, không có tài sản bảo đảm rõ ràng nhưng được thực hiện theo hợp đồng. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty không có nợ vay ngân hàng, nợ chủ yếu là phải trả ngắn hạn và dài hạn khác (phải trả người bán, thuế, quỹ phúc lợi...). Áp lực nợ thấp, thanh khoản tốt với tiền và đầu tư ngắn hạn lớn.', 'Hàng tồn kho giá trị thấp (khoảng 38 triệu VND) và không có dự phòng giảm giá. Dự án xây dựng dở dang tăng mạnh từ 1.9 tỷ lên 4.4 tỷ VND do đầu tư mở rộng hạ tầng bến xe, có thể mang lại lợi ích tương lai nhưng cần theo dõi tiến độ.', 3, 'Công ty có sức khỏe tài chính vững mạnh với doanh thu và lợi nhuận tăng trưởng ổn định, biên lợi nhuận gộp cao (trên 57%). Nợ vay gần như không có, dòng tiền hoạt động kinh doanh dương mạnh. Công ty đầu tư mở rộng hạ tầng và duy trì quỹ phúc lợi tốt. Quản trị minh bạch, giao dịch với bên liên quan được kiểm soát. Triển vọng đầu tư tích cực trong dài hạn.'),
('VXT_2025_consolidated', 'VXT', 2025, 'consolidated', 'Rủi ro liên quan đến bên liên quan ở mức TRUNG BÌNH. Công ty có các giao dịch với cổ đông nhà nước cũ (SCIC) liên quan khoản lãi chậm nộp vốn cổ phần hóa từ 2005-2011, đây là khoản nợ cũ chưa thanh toán. Công ty đã phân phối lợi nhuận năm 2024 vượt quá 905,414,948 VND so với lợi nhuận được phép sử dụng, và chưa trình Đại hội đồng cổ đông để xử lý. Thù lao HĐQT, BKS và Ban Giám đốc minh bạch, tổng khoảng 283 triệu VND/năm. Các khoản cho vay cá nhân của nhân viên Công ty mẹ không có tài sản thế chấp với lãi suất 6%/năm là điểm cần lưu ý.', 'Áp lực nợ vay ở mức TRUNG BÌNH-THẤP. Nợ vay ngắn hạn giảm mạnh từ 37.67 tỷ xuống 27.08 tỷ VND (-28%), phản ánh khả năng trả nợ cải thiện. Tuy nhiên, công ty phụ thuộc hoàn toàn vào nợ ngắn hạn với Agribank là chủ nợ chính. Nhiều tài sản thế chấp đã được sử dụng (xe ô tô, tiết kiệm, trái phiếu, tiền gửi có kỳ hạn). Khoản vay cá nhân 100 triệu VND từ nhân viên không có tài sản đảm bảo là rủi ro nhỏ. Công ty có dòng tiền hoạt động kinh doanh dương mạnh 16.60 tỷ VND, đủ khả năng trả nợ.', 'Rủi ro tồn kho ở mức THẤP. Hàng tồn kho giảm từ 22.01 tỷ xuống 17.24 tỷ VND, dự phòng giảm giá chỉ 40.8 triệu VND và không phát sinh thêm trong năm. Giá trị tồn kho chủ yếu là hàng hóa dầu mỡ, dung môi có thanh khoản tốt. Dự án xây dựng dở dang 20 Mạc Thị Bưởi với vốn đầu tư 130 tỷ VND mới đạt 1.75 tỷ VND (1.3%), chưa được cấp phép xây dựng, tiến độ chậm so với kế hoạch ban đầu (dự kiến hoàn thành Quý I/2026) là rủi ro cần theo dõi.', 6, 'Công ty Cổ phần Kho vận và Dịch vụ Thương mại có tình hình tài chính CẢI THIỆN trong năm 2025: lợi nhuận sau thuế tăng 158% (từ 2.26 tỷ lên 5.83 tỷ VND), biên lợi nhuận gộp đạt 22.1% (tăng từ 20.1%), dòng tiền hoạt động kinh doanh dương mạnh 16.6 tỷ VND. Nợ vay giảm 28% phản ánh khả năng trả nợ tốt. Tuy nhiên, điểm cần lưu ý: (1) Công ty đã phân phối cổ tức vượt mức cho phép 905 triệu VND chưa được ĐHĐCĐ phê duyệt, (2) Dự án đầu tư lớn 130 tỷ VND tại 20 Mạc Thị Bưởi tiến độ chậm và chưa có giấy phép, (3) Chi phí lãi vay tăng 27% lên 2.23 tỷ VND, (4) Công ty thanh lý/bổ nhiệm nhiều vị trí quản lý chủ chốt trong năm. Triển vọng trung hạn tích cực nếu dự án bất động sản được triển khai đúng tiến độ.'),
('WCS_2016_consolidated', 'WCS', 2016, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm công ty mẹ, cùng tập đoàn và công ty liên kết. Các giao dịch chủ yếu là cho vay, cung cấp dịch vụ và mua bán hàng hóa. Không có bằng chứng về giao dịch bất thường như cho vay không lãi suất hoặc chênh lệch giá lớn, nhưng sự tập trung giao dịch với bên liên quan có thể tạo rủi ro về độc lập kinh doanh.', 'Công ty chủ yếu có nợ ngắn hạn và dài hạn với các đối tượng khác nhau, nhưng nợ vay ngân hàng không rõ ràng. Áp lực nợ thấp do tỷ lệ nợ trên tổng tài sản thấp (khoảng 16.6% vào 31/12/2016). Công ty có đủ khả năng thanh toán với tài sản lưu động cao.', 'Hàng tồn kho có giá trị nhỏ (45 triệu VNĐ) và không có dự phòng giảm giá, cho thấy rủi ro thấp. Dự án xây dựng dở dang có giá trị tăng mạnh trong năm, nhưng không có thông tin về tiến độ hay khả năng hoàn thành, có thể tiềm ẩn rủi ro nếu dự án chậm trễ.', 4, 'Công ty có tình hình tài chính ổn định với lợi nhuận tăng trưởng, tỷ suất lợi nhuận gộp cao (khoảng 58.2% năm 2016). Tuy nhiên, doanh thu phụ thuộc lớn vào một số bên liên quan. Công ty có khả năng thanh toán tốt với tiền và đầu tư ngắn hạn dồi dào. Điểm rủi ro quản trị ở mức trung bình do giao dịch với bên liên quan phức tạp nhưng không có dấu hiệu gian lận.'),
('WCS_2018_consolidated', 'WCS', 2018, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm cho vay có lãi suất, cung cấp dịch vụ và mua hàng. Các giao dịch này dường như nằm trong hoạt động kinh doanh bình thường, nhưng cần theo dõi để đảm bảo tính công bằng và minh bạch.', 'Công ty không có nợ vay ngân hàng, nợ chủ yếu là phải trả người bán và các khoản ký quỹ dài hạn. Áp lực nợ thấp và khả năng thanh toán tốt, không có tài sản thế chấp đáng kể.', 'Hàng tồn kho có giá trị thấp, chủ yếu là nguyên vật liệu và hàng hóa. Các dự án xây dựng dở dang đang trong quá trình triển khai và không có dấu hiệu ứ đọng, rủi ro tồn kho thấp.', 4, 'Công ty có tình hình tài chính khỏe mạnh với doanh thu và lợi nhuận tăng trưởng, tỷ suất lợi nhuận gộp cao. Nợ thấp và dòng tiền ổn định. Tuy nhiên, cần quan tâm đến giao dịch với bên liên quan và tiến độ các dự án xây dựng.'),
('VXT_2025_parent', 'VXT', 2025, 'parent', 'Các giao dịch với bên liên quan chủ yếu là với công ty con, bao gồm bán hàng, mua hàng, nhận cổ tức và lãi vay. Lãi suất cho vay khoảng 8%/năm, không có dấu hiệu bất thường như cho vay không lãi suất hoặc chênh lệch giá lớn. Tuy nhiên, công ty có khoản phải thu lớn từ công ty con (902.400.000 VND) và lãi vay phải thu, cần giám sát khả năng thu hồi.', 'Nợ ngắn hạn chiếm tỷ trọng cao (4.600.000.000 VND) so với tiền mặt (984.385.398 VND), tạo áp lực thanh khoản. Tuy nhiên, công ty có các khoản đầu tư tài chính ngắn hạn (4.400.000.000 VND) và phải thu ngắn hạn lớn (16.734.699.236 VND) để bù đắp. Nợ vay chủ yếu từ bên liên quan với lãi suất hợp lý.', 'Hàng tồn kho có giá trị nhỏ (40.799.674 VND) và đã được trích lập dự phòng toàn bộ, không đáng lo ngại. Dự án xây dựng dở dang (1.747.183.482 VND) đang trong quá trình triển khai, cần theo dõi tiến độ và hiệu quả đầu tư.', 4, 'Công ty có kết quả kinh doanh khả quan với lợi nhuận tăng mạnh, biên lợi nhuận gộp cao (khoảng 70%). Tuy nhiên, cơ cấu nợ ngắn hạn cao và tập trung vào các khoản vay từ bên liên quan. Dòng tiền từ hoạt động kinh doanh dương, hỗ trợ thanh toán nợ. Rủi ro quản trị ở mức trung bình do có giao dịch với công ty con nhưng không phát hiện bất thường nghiêm trọng.'),
('VXT_2024_parent', 'VXT', 2024, 'parent', 'Công ty có giao dịch với công ty con (bán và mua hàng) và với cổ đông lớn (hoàn tạm ứng). Các giao dịch này là bình thường trong hoạt động kinh doanh, không có dấu hiệu bất thường rõ ràng. Giá trị giao dịch giảm mạnh so với năm trước do công ty đã chuyển giao hoạt động kinh doanh sang công ty con.', 'Nợ vay tổng cộng 4,65 tỷ VND, trong đó nợ dài hạn 4,5 tỷ từ công ty con. Áp lực nợ thấp do vốn chủ sở hữu lớn (62 tỷ) và dòng tiền từ hoạt động kinh doanh có thể đáp ứng được các nghĩa vụ nợ.', 'Hàng tồn kho thấp và đã trích lập dự phòng đầy đủ. Dự án xây dựng dở dang có tổng mức đầu tư 130 tỷ đang trong giai đoạn phê duyệt quy hoạch và cấp phép xây dựng, có thể gặp rủi ro chậm tiến độ.', 4, 'Công ty có sức khỏe tài chính cơ bản tốt với tỷ lệ nợ vay thấp và vốn chủ sở hữu mạnh. Tuy nhiên, doanh thu giảm mạnh do chuyển giao hoạt động kinh doanh cho công ty con và thu hồi đất. Triển vọng phụ thuộc vào hiệu quả của dự án xây dựng và hoạt động cho thuê kho bãi.'),
('VXT_2024_consolidated', 'VXT', 2024, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là thù lao cho ban lãnh đạo, không có giao dịch mua bán bất thường hoặc cho vay không lãi suất. Rủi ro thấp.', 'Nợ vay ngắn hạn chiếm tỷ trọng cao (37.67 tỷ VND), được đảm bảo bằng tài sản thế chấp. Áp lực trả nợ ngắn hạn nhưng có tài sản đảm bảo và dòng tiền kinh doanh. Rủi ro trung bình.', 'Hàng tồn kho là hàng hóa thông thường, dự phòng giảm giá nhỏ. Dự án xây dựng dở dang đang trong quá trình triển khai quy hoạch và xin phép xây dựng, có thể chậm tiến độ. Rủi ro trung bình.', 4, 'Doanh nghiệp có tình hình tài chính tương đối ổn định với doanh thu tăng nhưng lợi nhuận giảm do chi phí tăng. Nợ vay ngắn hạn cao nhưng có tài sản đảm bảo. Dòng tiền hoạt động kinh doanh âm trong năm nay. Triển vọng trung bình, phụ thuộc vào tiến độ dự án và điều kiện thị trường.'),
('VXT_2023_consolidated', 'VXT', 2023, 'consolidated', 'Công ty có phát sinh giao dịch với cổ đông và thành viên ban lãnh đạo, bao gồm tạm ứng, chi hộ, và các khoản vay cá nhân. Các giao dịch này được ghi nhận chi tiết và có vẻ là nghiệp vụ kinh doanh thông thường, tuy nhiên cần theo dõi tính công bằng của các điều khoản vay lãi suất 6%/năm cho cán bộ nhân viên.', 'Công ty có cấu trúc nợ ngắn hạn lớn (24.14 tỷ VND), tập trung chủ yếu vào vay ngân hàng với tài sản thế chấp là bất động sản, ô tô và tiết kiệm cá nhân. Áp lực trả nợ trong ngắn hạn là đáng kể, nhưng khả năng thanh toán được hỗ trợ bởi dòng tiền từ hoạt động kinh doanh và tài sản đáo hạn.', 'Tồn kho là hàng hóa kinh doanh với dự phòng giảm giá hơn 521 triệu VND, cho thấy một phần hàng hóa có nguy cơ chậm luân chuyển hoặc giảm giá trị. Dự án xây dựng dở dang mới bắt đầu nên rủi ro ứ đọng chưa cao.', 5, 'Công ty hoạt động trong lĩnh vực thương mại và dịch vụ kho vận. Sức khỏe tài chính ổn định với vốn chủ sở hữu tăng mạnh nhờ phát hành cổ phiếu. Doanh thu giảm so với năm trước do kinh tế khó khăn và thay đổi chiến lược kinh doanh. Công ty có tài sản cố định và bất động sản đầu tư lớn, là nền tảng cho hoạt động cho thuê. Rủi ro chính nằm ở áp lực nợ ngắn hạn và hiệu quả kinh doanh hàng hóa.'),
('VXT_2023_parent', 'VXT', 2023, 'parent', 'Doanh nghiệp có giao dịch lớn với công ty con, chiếm hơn 50% doanh thu, tạo rủi ro tập trung. Tuy nhiên, các giao dịch này có vẻ là thương mại bình thường. Ngoài ra, có phải thu từ chủ tịch công ty, nhưng số tiền không lớn.', 'Nợ vay giảm mạnh từ 27.8 tỷ xuống 150 triệu, áp lực nợ thấp. Công ty đã trả hết nợ ngân hàng dài hạn, chỉ còn nợ ngắn hạn nhỏ.', 'Hàng tồn kho rất thấp, chỉ 40 triệu, dự phòng nhỏ, không có rủi ro tồn kho dở dang. Dự án xây dựng dở dang đang triển khai.', 4, 'Công ty có sức khỏe tài chính ổn định với nợ vay thấp, dòng tiền kinh doanh dương. Tuy nhiên, doanh thu phụ thuộc nhiều vào công ty con, và lợi nhuận giảm so với năm trước. Triển vọng trung bình.');
PRAGMA foreign_keys = ON;
